                                    )}
                                    {detailTab === 'tasks' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-3 animate-fade-in max-w-2xl mx-auto pr-2">
                                            {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
                                                <button
                                                    key={task}
                                                    onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                    className={`w-full p-6 rounded-2xl border transition-all text-left shadow-lg ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100 ring-1 ring-yellow-500/50' : 'bg-black/30 border-white/5 hover:bg-black/50 hover:border-white/20 text-gray-400'}`}
                                                >
                                                    <p className="text-base font-bold mb-1">{TASK_INFO[task].label}</p>
                                                    <p className="text-xs opacity-60 leading-relaxed">{TASK_INFO[task].desc}</p>
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default ClanDashboard;

import React, { useState, useMemo, useCallback } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType, TalentTier, RootGrade, SpecializedTalents } from '../types';
import { 
    TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, 
    PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus, 
    getWeaponMasteryTitle, getWeaponTalentBonus, 
    PILL_DETAILS, HERB_DETAILS, 
    GENERATIONS, ALL_ITEM_DETAILS
} from '../constants';

/**
 * 根据品级获取对应的UI样式
 * 1-2品为白色；3品浅绿色、4品为深绿色；5品浅蓝色、6品为深蓝色；7品为紫色、8品为橙色、9品为红色
 */
const getGradeStyle = (grade: number | string | undefined) => {
    const g = typeof grade === 'number' ? grade : (grade === '神器残片' ? 9 : 0);

    // 1-2品：白色
    if (g <= 2) return {
        border: 'border-slate-300/60',
        text: 'text-slate-100',
        bg: 'bg-slate-900/60',
        hover: 'hover:border-slate-100',
        glow: 'shadow-[inset_0_0_10px_rgba(255,255,255,0.05)]',
        dropShadow: 'shadow-[0_0_5px_rgba(255,255,255,0.1)]'
    };
    // 3品：浅绿色
    if (g === 3) return {
        border: 'border-emerald-400/70',
        text: 'text-emerald-300',
        bg: 'bg-emerald-950/40',
        hover: 'hover:border-emerald-300',
        glow: 'shadow-[inset_0_0_12px_rgba(52,211,153,0.1)]',
        dropShadow: 'shadow-[0_0_8px_rgba(52,211,153,0.2)]'
    };
    // 4品：深绿色
    if (g === 4) return {
        border: 'border-green-700/80',
        text: 'text-green-400',
        bg: 'bg-green-950/50',
        hover: 'hover:border-green-500',
        glow: 'shadow-[inset_0_0_15px_rgba(21,128,61,0.15)]',
        dropShadow: 'shadow-[0_0_10px_rgba(21,128,61,0.3)]'
    };
    // 5品：浅蓝色
    if (g === 5) return {
        border: 'border-sky-400/80',
        text: 'text-sky-300',
        bg: 'bg-sky-950/40',
        hover: 'hover:border-sky-200',
        glow: 'shadow-[inset_0_0_15px_rgba(56,189,248,0.2)]',
        dropShadow: 'shadow-[0_0_12px_rgba(56,189,248,0.3)]'
    };
    // 6品：深蓝色
    if (g === 6) return {
        border: 'border-blue-700/90',
        text: 'text-blue-400',
        bg: 'bg-blue-950/50',
        hover: 'hover:border-blue-500',
        glow: 'shadow-[inset_0_0_18px_rgba(29,78,216,0.25)]',
        dropShadow: 'shadow-[0_0_15px_rgba(29,78,216,0.4)]'
    };
    // 7品：紫色
    if (g === 7) return {
        border: 'border-purple-600',
        text: 'text-purple-400',
        bg: 'bg-purple-950/40',
        hover: 'hover:border-purple-300',
        glow: 'shadow-[inset_0_0_20px_rgba(168,85,247,0.3)]',
        dropShadow: 'shadow-[0_0_18px_rgba(168,85,247,0.5)]'
    };
    // 8品：橙色
    if (g === 8) return {
        border: 'border-orange-500',
        text: 'text-orange-400',
        bg: 'bg-orange-950/40',
        hover: 'hover:border-orange-300',
        glow: 'shadow-[inset_0_0_22px_rgba(249,115,22,0.35)]',
        dropShadow: 'shadow-[0_0_20px_rgba(249,115,22,0.6)]'
    };
    // 9品：红色
    return {
        border: 'border-red-600',
        text: 'text-red-500',
        bg: 'bg-red-950/50',
        hover: 'hover:border-red-400',
        glow: 'shadow-[inset_0_0_25px_rgba(220,38,38,0.4)]',
        dropShadow: 'shadow-[0_0_25px_rgba(239,68,68,0.7)]'
    };
};

const getGradeColor = (grade: number | string | undefined) => {
    const style = getGradeStyle(grade);
    return `${style.border} ${style.text} ${style.dropShadow}`;
};

const getTierColor = (tier: TalentTier) => {
    switch (tier) {
        case '凡人': return 'text-slate-400';
        case '平庸': return 'text-gray-300';
        case '普通': return 'text-emerald-500';
        case '超凡': return 'text-sky-500';
        case '天才': return 'text-purple-500';
        case '绝世': return 'text-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]';
        case '绝世天骄': return 'text-rose-500 animate-pulse font-black shadow-[0_0_12px_rgba(244,63,94,0.6)]';
        default: return 'text-gray-400';
    }
};

const getTitleColor = (tier: TalentTier) => {
    switch (tier) {
        case '凡人': return 'text-white';
        case '平庸': return 'text-green-500';
        case '普通': return 'text-blue-400';
        case '超凡': return 'text-purple-500';
        case '天才': return 'text-orange-500';
        case '绝世': return 'text-amber-400';
        case '绝世天骄': return 'text-red-600';
        default: return 'text-white';
    }
};

const getRootGradeColor = (grade: RootGrade) => {
    switch (grade) {
        case '凡人': return 'text-slate-500';
        case '伪灵根': return 'text-gray-400';
        case '下品灵根': return 'text-emerald-600';
        case '中品灵根': return 'text-sky-600';
        case '极品灵根': return 'text-amber-600 font-bold';
        default: return 'text-gray-400';
    }
};

const getRealmStyle = (realm: Realm) => {
    if (realm === Realm.Mortal) return "border-[#4a3728] bg-[#2c1810] text-[#8c6b4f]";
    return "border-[#6b4e31] bg-[#3d2b1f] text-[#c9a063]";
};

const getRealmText = (realm: Realm, subRealm: number) => {
    if (realm === Realm.Mortal) return '凡人';
    return `${realm}${subRealm}层`;
};

const getGradeText = (method: CultivationMethod) => {
    const numerals = ['','一','二','三','四','五','六','七','八','九'];
    return `${numerals[method.grade]}品${method.quality}`;
};

const getElementColorClass = (key: string, val: number) => {
    if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
    switch (key) {
        case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
        case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
        case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
        case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
        case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
        default: return 'text-gray-400 border-gray-500';
    }
};

const getElementName = (key: string) => {
    switch (key) {
        case 'gold': return '金';
        case 'wood': return '木';
        case 'water': return '水';
        case 'fire': return '火';
        case 'earth': return '土';
        default: return key;
    }
};

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
    onOpenBreakthrough?: (id: string) => void;
}

const ITEMS_PER_PAGE = 8;
type BagSubTab = 'all' | 'equipment' | 'pills' | 'materials' | 'methods';
type SortKey = 'grade' | 'quantity' | 'name';

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember, onOpenBreakthrough }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'bag' | 'relations'>('attr');
    const [bagSubTab, setBagSubTab] = useState<BagSubTab>('all');
    const [bagSortKey, setBagSortKey] = useState<SortKey>('grade');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<number | null>(null);
    const [useQuantity, setUseQuantity] = useState<number>(1);
    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const isBreakthroughNeeded = (member: ClanMember) => {
        return member.subRealm === 9 && member.cultivationProgress >= 100 && member.realm !== Realm.YuanShen;
    };

    const toggleMethod = (methodId: number, type: MethodType) => {
        if (!selectedMember) return;

        // Check requirements before allowing study
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        if (method) {
            const meetsReq = checkMethodRequirements(selectedMember, method);
            if (!meetsReq) {
                // Here we could show a visual warning, but for now we just return
                return;
            }
        }

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
    };

    const checkMethodRequirements = (member: ClanMember, method: CultivationMethod) => {
        const req = method.requirements;
        if (!req) return true;

        // Realm check
        if (req.realm) {
            if (REALM_ORDER.indexOf(member.realm) < REALM_ORDER.indexOf(req.realm)) return false;
        }

        // Roots check
        if (req.minRoots) {
            for (const [key, val] of Object.entries(req.minRoots)) {
                if ((member.roots as any)[key] < (val || 0)) return false;
            }
        }

        // Root Grade check
        if (req.minRootGrade) {
            const grades: RootGrade[] = ['凡人', '伪灵根', '下品灵根', '中品灵根', '极品灵根'];
            if (grades.indexOf(member.rootGrade) < grades.indexOf(req.minRootGrade)) return false;
        }

        return true;
    };

    const libraryMethods = useMemo(() => {
        if (!selectedMember) return [];
        return CULTIVATION_METHODS.filter(m => {
            if (m.type !== libraryType) return false;
            const isOwnedByClan = (state.inventory.methods[m.id] || 0) > 0;
            const isOwnedBySelf = (selectedMember.personalInventory.methods[m.id] || 0) > 0;
            const isEquipped = selectedMember.mainMethodId === m.id || 
                             selectedMember.movementMethodId === m.id || 
                             selectedMember.auxMethodIds.includes(m.id);
            return isOwnedByClan || isOwnedBySelf || isEquipped;
        }).map(m => {
            const totalCount = (state.inventory.methods[m.id] || 0) + (selectedMember.personalInventory.methods[m.id] || 0);
            return { ...m, totalCount };
        });
    }, [libraryType, selectedMember, state.inventory.methods]);

    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;

        if (rect.top < 300) {
            y = rect.bottom + 12;
        } else {
            y = rect.top - 12;
        }

        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;

        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => {
        const req = method.requirements;
        const meetsRealm = !req?.realm || REALM_ORDER.indexOf(selectedMember?.realm || Realm.Mortal) >= REALM_ORDER.indexOf(req.realm);

        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                        {getGradeText(method)}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-2 leading-relaxed italic">{method.desc}</p>

                {/* Requirements Section */}
                <div className="mb-3 p-1.5 bg-black/30 border border-yellow-900/10 rounded">
                    <p className="text-[10px] text-orange-400 font-bold mb-1">【修炼要求】</p>
                    {req?.realm && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">境界要求</span>
                            <span className={meetsRealm ? 'text-green-500' : 'text-red-500'}>{req.realm}</span>
                        </div>
                    )}
                    {req?.minRootGrade && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">灵根等级</span>
                            <span className={`text-right ${selectedMember && (['凡人', '伪灵根', '下品灵根', '中品灵根', '极品灵根'].indexOf(selectedMember.rootGrade) >= ['凡人', '伪灵根', '下品灵根', '中品灵根', '极品灵根'].indexOf(req.minRootGrade)) ? 'text-gray-300' : 'text-red-500'}`}>{req.minRootGrade}</span>
                        </div>
                    )}
                    {req?.minRoots && Object.entries(req.minRoots).map(([key, val]) => {
                        const memberVal = selectedMember ? (selectedMember.roots as any)[key] : 0;
                        const meetsVal = memberVal >= (val || 0);
                        return (
                            <div key={key} className="flex justify-between text-[10px]">
                                <span className="text-gray-500">{getElementName(key)}灵根</span>
                                <span className={`text-right ${meetsVal ? 'text-gray-300' : 'text-red-500'}`}>≥ {val}</span>
                            </div>
                        );
                    })}
                    {!req?.realm && !req?.minRoots && !req?.minRootGrade && (
                        <p className="text-[9px] text-gray-600">无特殊要求</p>
                    )}
                </div>

                <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                    <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                    {method.buffs.cultivationSpeed && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">修炼速度</span>
                            <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                                {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                            </span>
