    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemId = selectedMember.equippedItems[slot];
        if (itemId === null) return;

        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };

        newInventory.weapons[itemId] = (newInventory.weapons[itemId] || 0) + 1;

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemId: number, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;

        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };

        const currentItemId = newEquipped[category];
        if (currentItemId !== null) {
            newInventory.weapons[currentItemId] = (newInventory.weapons[currentItemId] || 0) + 1;
        }

        if (newInventory.weapons[itemId] > 0) {
            newInventory.weapons[itemId]--;
            if (newInventory.weapons[itemId] === 0) delete newInventory.weapons[itemId];
        }

        newEquipped[category] = itemId;

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedBagItem(null);
    };

    const handleUsePill = (pillId: number, quantity: number) => {
        if (!selectedMember) return;

        const pillData = PILL_DETAILS[pillId] as any;
        if (!pillData) return;

        if (pillData.requiredRealm && selectedMember.realm !== pillData.requiredRealm) {
            setFocusedBagItem(null);
            hideTooltip();
            return;
        }

        const newInventory = { ...selectedMember.personalInventory };
        const currentCount = newInventory.pills[pillId] || 0;
        if (currentCount < quantity) return;

        newInventory.pills[pillId] -= quantity;
        if (newInventory.pills[pillId] === 0) delete newInventory.pills[pillId];

        const updates: Partial<ClanMember> = { personalInventory: newInventory };

        const pillEffects = pillData.effects;
        if (pillEffects) {
            if (pillEffects.cultivationProgress) {
                updates.cultivationProgress = (selectedMember.cultivationProgress || 0) + (pillEffects.cultivationProgress * quantity);
            }
            if (pillEffects.status) {
                updates.status = pillEffects.status;
            }
            if (pillEffects.maxAge) {
                updates.maxAge = (selectedMember.maxAge || 0) + (pillEffects.maxAge * quantity);
            }
            if (pillEffects.divineSense) {
                updates.divineSense = (selectedMember.divineSense || 0) + (pillEffects.divineSense * quantity);
            }
        }

        onUpdateMember(selectedMember.id, updates);
        setFocusedBagItem(null);
        setUseQuantity(1);
        hideTooltip();
    };

