                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500 hover:text-gray-400'}`}>英灵祠堂</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                {activeTab === 'alive' && (
                    <button onClick={onAddMember} className="w-full bg-green-900/20 hover:bg-green-800/40 text-green-400 border border-green-900/50 py-2 rounded text-xs transition-all flex items-center justify-center gap-2 mb-4 group">
                        <span>👶</span> 诞育麟儿
                    </button>
                )}
                {pagedMembers.length > 0 ? pagedMembers.map(m => {
                    const needsBreakthrough = isBreakthroughNeeded(m);
                    return (
                        <div 
                            key={m.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(m.id)}
                            className={`group p-3 rounded-md border transition-all cursor-pointer animate-fade-in ${selectedMemberId === m.id ? 'bg-[#2d1e15] border-yellow-600 scale-[1.02] shadow-xl' : 'bg-[#1e130c] border-yellow-900/30 hover:border-yellow-700/50'}`}
                        >
                            <div className="flex justify-between items-start mb-1">
                                <div className="flex items-center gap-2">
                                    <span className="font-bold text-sm text-yellow-100/90">{m.name}</span>
                                    <span className="text-[8px] text-[#8c6b4f]">[{m.position}]</span>
                                    {m.assignment === 'Cultivation' && m.realm !== Realm.Mortal && <span className="text-[8px] animate-pulse text-blue-400">修炼中</span>}
                                    {needsBreakthrough && <span className="text-[8px] bg-red-900 text-white px-1 animate-bounce rounded-sm">瓶颈</span>}
                                </div>
                                <button className={`text-[9px] px-2 py-0.5 rounded border shadow-sm hover:brightness-125 transition-all ${getRealmStyle(m.realm)}`}>
                                    {getRealmText(m.realm, m.subRealm)}
                                </button>
                            </div>
                            <div className="flex justify-between text-[10px] text-gray-500 items-baseline">
                                <span>评级：<span className={`font-black ${getTierColor(m.tier)}`}>{m.tier}</span></span>
                                <span className={`text-[9px] opacity-80 italic font-sans ${getRootGradeColor(m.rootGrade)}`}>{m.rootGrade}</span>
                            </div>
                            {activeTab === 'alive' && m.realm !== Realm.Mortal && (
                                <div className="mt-2 w-full h-1 bg-black/40 rounded-full overflow-hidden border border-white/5">
                                    <div 
                                        className={`h-full transition-all duration-1000 ${needsBreakthrough ? 'bg-red-600 shadow-[0_0_8px_rgba(220,38,38,0.8)]' : 'bg-blue-500/60'}`} 
                                        style={{ width: `${m.cultivationProgress}%` }}
                                    ></div>
                                </div>
                            )}
                        </div>
                    );
                }) : (
                    <div className="py-20 text-center text-gray-700 opacity-40 italic">空空如也</div>
                )}
            </div>

            {selectedMember && activeTab === 'alive' && (
                <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/95 p-2 sm:p-4 font-serif overflow-hidden">
                    <div className="relative w-full max-w-6xl max-h-[95vh] h-full bg-[#1a2521] border-[4px] sm:border-[12px] border-[#2c3e34] rounded-sm shadow-2xl overflow-hidden flex flex-col">
                        <div className="h-20 sm:h-24 bg-[#141e1b] border-b border-[#2c3e34] flex items-center px-2 sm:px-8 shrink-0 pt-2">
                            <div className="flex items-center gap-1 sm:gap-2 h-full overflow-x-auto scrollbar-hide">
                                <button onClick={() => setDetailTab('attr')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'attr' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>👤 属性</button>
                                <button onClick={() => setDetailTab('talents')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'talents' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>📜 天赋</button>
                                <button onClick={() => setDetailTab('relations')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'relations' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🤝 关系</button>
                                <button onClick={() => setDetailTab('cultivation')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'cultivation' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🌀 功法</button>
                                <button onClick={() => setDetailTab('bag')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'bag' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🎒 行囊</button>
                                <button onClick={() => setDetailTab('plan')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'plan' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-300'}`}>🗺️ 计划</button>
                                <button onClick={() => setDetailTab('tasks')} className={`whitespace-nowrap px-3 sm:px-4 h-full flex items-center text-[11px] sm:text-sm transition-all border-b-4 font-bold ${detailTab === 'tasks' ? 'border-yellow-500 text-yellow-500 bg-yellow-900/10' : 'border-transparent text-gray-500 hover:text-gray-400'}`}>🎯 指派</button>
                            </div>
                            <button onClick={() => setSelectedMemberId(null)} className="ml-auto min-w-[36px] w-9 h-9 bg-red-900/20 hover:bg-red-900/40 text-red-500 rounded-full flex items-center justify-center text-xl transition-all font-bold">×</button>
                        </div>

                        <div className="flex-1 flex flex-col sm:flex-row overflow-hidden">
                            <div className="w-full sm:w-[35%] lg:w-[38%] flex flex-col items-center justify-start border-r border-[#2c3e34] p-4 sm:p-8 bg-black/10 shrink-0 pt-8 sm:pt-10 overflow-y-auto custom-scrollbar">
                                <div className="mb-6 w-full flex justify-center scale-90 sm:scale-100">
                                    {renderNamePlaque(selectedMember)}
                                </div>
                                <div className="relative flex items-center justify-center gap-4 sm:gap-6 py-4">
                                    <div className="flex flex-col gap-8">
                                        {renderEquipSlot(selectedMember.equippedItems.weapon, '武器', '⚔️', 'weapon')}
                                        {renderEquipSlot(selectedMember.equippedItems.armor, '防具', '🛡️', 'armor')}
                                    </div>
                                    <div className="w-28 h-40 lg:w-44 lg:h-64 bg-black/40 rounded-full border-2 border-yellow-900/20 relative flex items-center justify-center">
                                        <div className="text-6xl lg:text-8xl opacity-10">🧘</div>
                                    </div>
                                    <div className="flex flex-col gap-8">
                                        {renderEquipSlot(selectedMember.equippedItems.accessory, '饰品', '💍', 'accessory')}
                                        {renderEquipSlot(selectedMember.equippedItems.treasure, '法宝', '🔮', 'treasure')}
                                    </div>
                                </div>

                                <div className="mt-4 text-center">
                                    <p className={`text-xl sm:text-2xl font-bold tracking-widest ${isBreakthroughNeeded(selectedMember) ? 'text-red-600 animate-pulse' : 'text-blue-500'}`}>
                                        {getRealmText(selectedMember.realm, selectedMember.subRealm)}
                                    </p>
                                </div>

                                <div className="w-full mt-8 p-3 bg-black/30 border border-yellow-900/10 rounded">
                                    <div className="flex justify-between items-center mb-2">
                                        <h4 className="text-[10px] text-gray-500 font-bold uppercase">灵力状态</h4>
                                        {isBreakthroughNeeded(selectedMember) && (
                                            <span className="text-[9px] text-red-500 font-bold animate-pulse">瓶颈已至</span>
                                        )}
                                    </div>
                                    <div className="w-full h-2 bg-gray-900 rounded-full overflow-hidden border border-white/10">
                                        <div 
                                            className={`h-full transition-all duration-1000 ${isBreakthroughNeeded(selectedMember) ? 'bg-red-600 shadow-[0_0_8px_rgba(220,38,38,0.8)]' : 'bg-blue-600 shadow-[0_0_8px_rgba(37,99,235,0.6)]'}`} 
                                            style={{ width: `${selectedMember.cultivationProgress}%` }}
                                        ></div>
                                    </div>
                                </div>

                                {isBreakthroughNeeded(selectedMember) && (
                                    <button 
                                        onClick={() => onOpenBreakthrough?.(selectedMember.id)}
                                        className="mt-6 w-full py-3 bg-gradient-to-r from-red-900 to-red-700 text-white font-bold rounded-sm border border-red-500 shadow-[0_0_20px_rgba(239,68,68,0.4)] animate-pulse hover:brightness-125 transition-all text-sm tracking-widest"
                                    >
