                                    </button>
                                )}
                            </div>

                            <div className="flex-1 p-4 sm:p-8 lg:p-10 overflow-hidden bg-[#1a2521]/50 flex flex-col min-h-0">
                                <div className="flex-1 min-h-0">
                                    {detailTab === 'attr' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-10 animate-fade-in pr-2">
                                            <div className="grid grid-cols-1 md:grid-cols-2 gap-10">
                                                <div>
                                                    <h4 className="text-yellow-600 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-yellow-900/20 pb-2 mb-6">基础属性</h4>
                                                    <div className="grid grid-cols-2 gap-y-4 gap-x-6 text-sm">
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">性别：</span>
