                                                            <span className={`font-bold ${selectedMember.maxAge - selectedMember.age < 10 ? 'text-red-500 animate-pulse' : 'text-green-500'}`}>
                                                                {selectedMember.age} / {selectedMember.maxAge} 载
                                                            </span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">职位：</span>
                                                            <span className="text-orange-500 font-bold">{selectedMember.position}</span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">当前任务：</span>
                                                            <span className={`${TASK_INFO[selectedMember.assignment].color} font-bold`}>{TASK_INFO[selectedMember.assignment].label}</span>
                                                        </div>
                                                    </div>
                                                </div>
                                                <div>
                                                    <h4 className="text-blue-600 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-blue-900/20 pb-2 mb-6">修行天赋</h4>
                                                    <div className="grid grid-cols-2 gap-y-4 gap-x-6 text-sm">
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">资质：</span>
                                                            <span className="text-yellow-500 font-bold">{selectedMember.aptitude}</span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">悟性：</span>
                                                            <span className="text-purple-400 font-bold">{selectedMember.comprehension}</span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">神识：</span>
                                                            <span className="text-cyan-400 font-bold">{selectedMember.divineSense}</span>
                                                        </div>
                                                        <div className="flex justify-between border-b border-white/5 pb-2">
                                                            <span className="text-gray-500">体质：</span>
                                                            <div className="relative">
                                                                <span 
                                                                    onMouseEnter={(e) => showTooltip(e, renderPhysiqueTooltipContent(selectedMember.physique))}
