                                                                    className="text-pink-500 font-bold cursor-help underline underline-offset-4 decoration-dotted"
                                                                >
                                                                    {selectedMember.physique}
                                                                </span>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </div>
                                            </div>

                                            <div>
                                                <h4 className="text-yellow-600 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-yellow-900/20 pb-2 mb-8">
