                                                        </div>
                                                    ))}
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'relations' && renderRelationsTab()}

                                    {detailTab === 'bag' && renderBagTab()}

                                    {detailTab === 'talents' && (
