                                                                    <span className="text-xl font-bold text-red-500 font-mono">{val}</span>
                                                                </div>
                                                                <p className="text-sm font-bold text-orange-400 mb-2">{title}</p>
                                                                <div className="flex justify-between text-[11px] mb-2">
                                                                    <span className="text-gray-500">当前熟练度:</span>
                                                                    <span className="text-gray-200 font-mono">{prof}</span>
                                                                </div>
                                                                {bonus > 0 && <p className="text-[10px] text-green-500 font-bold">习练加成: +{bonus}%</p>}
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                            <div>
                                                <h4 className="text-blue-600 text-[15px] font-bold uppercase tracking-[0.3em] border-b border-blue-900/20 pb-2 mb-6">🧪 百艺修持</h4>
                                                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
                                                    {(Object.entries(selectedMember.talents.百艺天赋) as [string, number][]).filter(([_, val]) => val > 0).map(([key, val]) => {
                                                        const prof = selectedMember.proficiencies[key as keyof SpecializedTalents['百艺天赋']] || 0;
                                                        const title = getArtisanTitle(key, prof);
                                                        const successBonus = getArtisanBonus(val);
                                                        return (
                                                            <div key={key} className="bg-black/30 p-5 rounded-xl border border-blue-900/20 relative group overflow-hidden shadow-lg">
                                                                <div className="flex justify-between items-center mb-3">
                                                                    <span className="text-[11px] text-gray-400 font-bold">{key}天赋</span>
                                                                    <span className="text-xl font-bold text-blue-500 font-mono">{val}</span>
                                                                </div>
                                                                <p className="text-sm font-bold text-yellow-500 mb-2">{title}</p>
                                                                <div className="flex justify-between items-center text-[11px] mb-2">
                                                                    <span className="text-gray-500">当前熟练度:</span>
                                                                    <span className="text-blue-300 font-mono">{prof}</span>
                                                                </div>
                                                                {successBonus > 0 && <p className="text-[11px] text-green-500 font-bold">属性加成: +{successBonus}%</p>}
                                                                <div className="absolute -bottom-4 -right-4 opacity-5 text-5xl group-hover:scale-110 group-hover:rotate-12 transition-all">⚙️</div>
                                                            </div>
                                                        );
                                                    })}
                                                </div>
                                            </div>
                                        </div>
                                    )}

                                    {detailTab === 'cultivation' && renderCultivationTab()}

                                    {detailTab === 'plan' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-3 animate-fade-in max-w-2xl mx-auto pr-2">
                                            {(Object.keys(DEVELOPMENT_PLANS) as DevelopmentPlan[]).map(planKey => (
                                                <button
                                                    key={planKey}
                                                    onClick={() => onUpdateMember(selectedMember.id, { developmentPlan: planKey })}
                                                    className={`w-full p-6 rounded-2xl border transition-all text-left shadow-lg ${selectedMember.developmentPlan === planKey ? 'bg-purple-900/20 border-purple-500 ring-1 ring-purple-500/50' : 'bg-black/30 border-white/5 hover:bg-black/50 hover:border-white/20'}`}
                                                >
                                                    <p className="text-base font-bold text-white mb-1">{DEVELOPMENT_PLANS[planKey].label}</p>
                                                    <p className="text-xs text-gray-500 leading-relaxed">{DEVELOPMENT_PLANS[planKey].desc}</p>
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                    {detailTab === 'tasks' && (
                                        <div className="h-full overflow-y-auto custom-scrollbar space-y-3 animate-fade-in max-w-2xl mx-auto pr-2">
                                            {(Object.keys(TASK_INFO) as TaskType[]).map(task => (
                                                <button
                                                    key={task}
                                                    onClick={() => onUpdateMember(selectedMember.id, { assignment: task })}
                                                    className={`w-full p-6 rounded-2xl border transition-all text-left shadow-lg ${selectedMember.assignment === task ? 'bg-yellow-900/20 border-yellow-500 text-yellow-100 ring-1 ring-yellow-500/50' : 'bg-black/30 border-white/5 hover:bg-black/50 hover:border-white/20 text-gray-400'}`}
                                                >
                                                    <p className="text-base font-bold mb-1">{TASK_INFO[task].label}</p>
                                                    <p className="text-xs opacity-60 leading-relaxed">{TASK_INFO[task].desc}</p>
                                                </button>
                                            ))}
                                        </div>
                                    )}
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

