                </div>

                <div className="flex-2 bg-black/40 rounded-xl p-3 sm:p-4 border border-white/5 flex flex-col min-h-0 shadow-inner overflow-hidden">
                    <div className="flex flex-col sm:flex-row items-center justify-between mb-3 border-b border-white/10 pb-2 shrink-0">
                        <div className="flex items-center gap-3">
                            <h5 className="text-xs sm:text-sm text-gray-300 font-bold tracking-widest font-cursive whitespace-nowrap">功法</h5>
                            <div className="flex bg-black/60 p-0.5 rounded-md border border-white/5">
                                {[
                                    { id: 'Cultivation', name: '修行' },
                                    { id: 'Combat', name: '战斗' },
                                    { id: 'Movement', name: '遁术' }
                                ].map(tab => (
                                    <button 
                                        key={tab.id}
                                        onClick={() => setLibraryType(tab.id as MethodType)}
                                        className={`px-3 sm:px-4 py-0.5 text-[9px] sm:text-[10px] font-bold transition-all rounded whitespace-nowrap ${libraryType === tab.id ? 'bg-red-900/60 text-white shadow-sm' : 'text-gray-500 hover:text-gray-300'}`}
                                    >
                                        {tab.name}
                                    </button>
                                ))}
                            </div>
                        </div>
                        <span className="text-[8px] text-gray-600 mt-1 sm:mt-0 italic hidden md:inline">※ 持有功法一览</span>
                    </div>

                    <div className="flex-1 overflow-y-auto custom-scrollbar pr-1">
                        <div className="grid grid-cols-3 sm:grid-cols-4 lg:grid-cols-5 xl:grid-cols-6 gap-2 sm:gap-3 pb-4">
                            {libraryMethods.map(method => {
                                const isEquipped = selectedMember.mainMethodId === method.id || 
                                                 selectedMember.movementMethodId === method.id || 
                                                 selectedMember.auxMethodIds.includes(method.id);
                                const meetsReq = checkMethodRequirements(selectedMember, method);
                                const style = getGradeStyle(method.grade);
                                return (
                                    <div 
                                        key={method.id}
                                        onClick={() => !isEquipped && meetsReq && toggleMethod(method.id, method.type)}
                                        onMouseEnter={(e) => showTooltip(e, renderMethodTooltipContent(method))}
                                        onMouseLeave={hideTooltip}
                                        className={`p-2 sm:p-3 rounded-lg border transition-all cursor-pointer relative flex flex-col items-center justify-between aspect-[4/5] shadow-md group overflow-hidden
                                            ${style.border} ${style.bg} ${style.dropShadow} 
                                            ${isEquipped ? 'opacity-40 cursor-default grayscale border-gray-800 bg-black/60 shadow-none' : 
                                              (!meetsReq ? 'opacity-50 grayscale border-red-900/30 cursor-not-allowed' : 'hover:scale-[1.03] active:scale-95 hover:brightness-110')}`}
                                    >
                                        <div className="text-xl sm:text-2xl mt-1 opacity-90 group-hover:scale-110 transition-transform relative z-10">📜</div>
                                        <div className="text-center mt-1.5 flex-1 flex flex-col justify-center overflow-hidden w-full relative z-10">
                                            <p className={`text-[9px] sm:text-[10px] font-bold leading-tight px-0.5 truncate ${style.text}`}>{method.name}</p>
                                            <p className={`text-[7px] sm:text-[8px] font-bold mt-1 py-0 px-1.5 rounded-full border bg-black/40 mx-auto w-fit ${style.border}`}>
                                                {method.quality}
                                            </p>
                                        </div>

                                        <div className="w-full pt-1.5 border-t border-white/5 mt-1.5 flex justify-center relative z-10">
                                            <span className="text-[7px] sm:text-[8px] font-bold opacity-60 font-mono">品级:{method.grade}</span>
                                        </div>

                                        {isEquipped && (
                                            <div className="absolute inset-0 bg-black/20 flex items-center justify-center pointer-events-none z-20">
                                                <div className="bg-gray-800/90 text-white text-[7px] px-1.5 py-0.5 rounded-sm border border-white/10 rotate-[12deg] shadow-lg font-bold">
                                                    已修习
                                                </div>
                                            </div>
                                        )}
                                        {!meetsReq && !isEquipped && (
                                            <div className="absolute inset-0 bg-red-950/20 flex items-center justify-center pointer-events-none z-20">
                                                <div className="bg-red-900/90 text-white text-[7px] px-1.5 py-0.5 rounded-sm border border-red-500/50 -rotate-[12deg] shadow-lg font-bold">
                                                    条件不足
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    const renderRelationsTab = () => {
        if (!selectedMember) return null;

        const findMember = (id?: string | null) => state.members.find(m => m.id === id);

        const father = findMember(selectedMember.fatherId);
        const mother = findMember(selectedMember.motherId);
        const spouse = findMember(selectedMember.spouseId);
        const mentor = findMember(selectedMember.mentorId);

        const children = state.members.filter(m => m.fatherId === selectedMember.id || m.motherId === selectedMember.id);
        const siblings = state.members.filter(m => 
            m.id !== selectedMember.id && 
            (m.fatherId === selectedMember.fatherId && selectedMember.fatherId !== null) &&
            (m.motherId === selectedMember.motherId && selectedMember.motherId !== null)
        );
        const disciples = state.members.filter(m => m.mentorId === selectedMember.id);

        const MemberCard = ({ member: m, label, icon }: { member: ClanMember, label: string, icon: string }) => (
            <div 
                onClick={() => setSelectedMemberId(m.id)}
                className="bg-black/30 border border-yellow-900/20 p-3 rounded-lg flex items-center gap-3 hover:border-yellow-500/50 transition-all cursor-pointer group shadow-lg"
            >
                <div className="w-10 h-10 rounded-full bg-yellow-900/10 flex items-center justify-center border border-yellow-900/30 text-xl group-hover:scale-110 transition-transform">
                    {icon}
                </div>
                <div className="flex-1">
                    <div className="flex justify-between items-center">
                        <span className="text-xs font-bold text-yellow-100">{m.name}</span>
                        <span className="text-[8px] text-gray-500 bg-black/40 px-1.5 py-0.5 rounded border border-white/5">{label}</span>
                    </div>
                    <div className="flex justify-between items-center mt-1">
                        <span className={`text-[9px] ${getRealmStyle(m.realm).split(' ')[2]}`}>{getRealmText(m.realm, m.subRealm)}</span>
                        <span className={`text-[9px] font-black ${getTierColor(m.tier)}`}>{m.tier}</span>
                    </div>
                </div>
            </div>
        );

        const Section = ({ title, children: sectionChildren, icon }: { title: string, children: React.ReactNode, icon: string }) => (
            <div className="space-y-3">
                <h4 className="text-yellow-600 text-[12px] font-bold uppercase tracking-[0.2em] border-b border-yellow-900/10 pb-1 flex items-center gap-2">
                    <span>{icon}</span> {title}
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {sectionChildren}
                </div>
            </div>
        );

        return (
            <div className="h-full overflow-y-auto custom-scrollbar space-y-8 animate-fade-in pr-2 pt-2 pb-10">
                <div className="bg-black/20 p-4 rounded-xl border border-yellow-900/10 flex items-center justify-between">
                    <div>
                        <p className="text-xs text-gray-500">当前辈分</p>
                        <p className="text-2xl font-cursive text-yellow-500 mt-1">
                            {GENERATIONS[selectedMember.generation] || '通'} 字辈
                        </p>
                    </div>
                    <div className="text-right">
                        <p className="text-xs text-gray-500">家族地位</p>
                        <p className="text-sm font-bold text-orange-400 mt-1">{selectedMember.position}</p>
                    </div>
                </div>

                {(father || mother || spouse) && (
                    <Section title="至亲眷属" icon="💍">
                        {father && <MemberCard member={father} label="尊父" icon="👴" />}
                        {mother && <MemberCard member={mother} label="慈母" icon="👵" />}
                        {spouse && <MemberCard member={spouse} label="道侣" icon="💍" />}
                    </Section>
                )}

                {siblings.length > 0 && (
                    <Section title="同胞兄弟" icon="🤝">
                        {siblings.map(m => <MemberCard key={m.id} member={m} label="同胞" icon="🤝" />)}
                    </Section>
                )}

                {children.length > 0 && (
                    <Section title="膝下子女" icon="👶">
                        {children.map(m => <MemberCard key={m.id} member={m} label="子女" icon="👶" />)}
                    </Section>
                )}

                {(mentor || disciples.length > 0) && (
                    <Section title="宗门承传" icon="🎓">
                        {mentor && <MemberCard member={mentor} label="恩师" icon="🎓" />}
                        {disciples.map(m => <MemberCard key={m.id} member={m} label="门生" icon="✍️" />)}
                    </Section>
                )}
            </div>
        );
    };

    const sortedBagItems = useMemo(() => {
        if (!selectedMember) return [];
        const inv = selectedMember.personalInventory;

        const itemsList: Array<{ id: number; count: number; category: BagSubTab }> = [];

        const addItemsToList = (record: Record<number, number>, category: BagSubTab) => {
            Object.entries(record).forEach(([id, count]) => {
                if (count > 0) itemsList.push({ id: parseInt(id), count, category });
            });
        };

        if (bagSubTab === 'all' || bagSubTab === 'equipment') addItemsToList(inv.weapons, 'equipment');
        if (bagSubTab === 'all' || bagSubTab === 'pills') addItemsToList(inv.pills, 'pills');
        if (bagSubTab === 'all' || bagSubTab === 'materials') {
            addItemsToList(inv.herbs, 'materials');
            addItemsToList(inv.minerals, 'materials');
        }
        if (bagSubTab === 'all' || bagSubTab === 'methods') addItemsToList(inv.methods, 'methods');

        return itemsList.sort((a, b) => {
            const detailA = ALL_ITEM_DETAILS[a.id];
            const detailB = ALL_ITEM_DETAILS[b.id];
            if (!detailA || !detailB) return 0;

            if (bagSortKey === 'grade') {
                const gradeA = typeof detailA.grade === 'number' ? detailA.grade : (detailA.grade === '神器残片' ? 9 : 0);
                const gradeB = typeof detailB.grade === 'number' ? detailB.grade : (detailB.grade === '神器残片' ? 9 : 0);
                return gradeB - gradeA;
            } else if (bagSortKey === 'quantity') {
                return b.count - a.count;
            } else {
                return detailA.name.localeCompare(detailB.name, 'zh-CN');
            }
        });
    }, [selectedMember, bagSubTab, bagSortKey]);

    const renderBagTab = () => {
        if (!selectedMember) return null;
        return (
            <div className="h-full flex flex-col min-h-0 animate-fade-in pr-2 overflow-hidden">
                <div className="flex flex-wrap items-center justify-between gap-4 mb-4 shrink-0">
                    <div className="flex flex-wrap gap-2 p-1 bg-black/40 rounded-xl border border-yellow-900/20 w-fit">
                        <button onClick={() => setBagSubTab('all')} className={`px-3 sm:px-5 py-2 text-[10px] sm:text-xs rounded-lg transition-all font-bold ${bagSubTab === 'all' ? 'bg-yellow-700 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>📦 全部</button>
                        <button onClick={() => setBagSubTab('equipment')} className={`px-3 sm:px-5 py-2 text-[10px] sm:text-xs rounded-lg transition-all font-bold ${bagSubTab === 'equipment' ? 'bg-yellow-800 text-yellow-100 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>🏮 装备</button>
                        <button onClick={() => setBagSubTab('pills')} className={`px-3 sm:px-5 py-2 text-[10px] sm:text-xs rounded-lg transition-all font-bold ${bagSubTab === 'pills' ? 'bg-pink-900/40 text-pink-200' : 'text-gray-500 hover:text-gray-300'}`}>💊 丹药</button>
                        <button onClick={() => setBagSubTab('materials')} className={`px-3 sm:px-5 py-2 text-[10px] sm:text-xs rounded-lg transition-all font-bold ${bagSubTab === 'materials' ? 'bg-emerald-900/40 text-emerald-200' : 'text-gray-500 hover:text-gray-300'}`}>🎋 材料</button>
                        <button onClick={() => setBagSubTab('methods')} className={`px-3 sm:px-5 py-2 text-[10px] sm:text-xs rounded-lg transition-all font-bold ${bagSubTab === 'methods' ? 'bg-amber-900/40 text-amber-200' : 'text-gray-500 hover:text-gray-300'}`}>📜 功法</button>
                    </div>

                    <div className="flex items-center gap-2 bg-black/20 p-1 rounded-lg border border-white/5">
                        <span className="text-[10px] text-gray-500 px-2 font-bold border-r border-white/10">排序</span>
                        <select 
                            value={bagSortKey}
                            onChange={(e) => setBagSortKey(e.target.value as SortKey)}
                            className="bg-transparent text-[10px] sm:text-xs text-yellow-600 outline-none font-bold cursor-pointer px-1"
                        >
                            <option value="grade">按品级</option>
                            <option value="quantity">按数量</option>
                            <option value="name">按名称</option>
                        </select>
                    </div>
                </div>

                <div className="flex-1 overflow-y-auto custom-scrollbar pb-10">
                    {sortedBagItems.length > 0 ? (
                        <div className="grid grid-cols-2 sm:grid-cols-4 lg:grid-cols-5 gap-4">
                            {sortedBagItems.map(item => {
                                let itemIcon = '❓';
                                let itemActionLabel: string | undefined = undefined;
                                let itemOnAction: ((qty: number) => void) | undefined = undefined;

                                const detail = ALL_ITEM_DETAILS[item.id];

                                if (item.category === 'equipment') {
                                    itemIcon = '⚔️'; 
                                    itemActionLabel = '佩戴';
                                    itemOnAction = () => handleEquip(item.id, 'weapon');
                                } else if (item.category === 'pills') {
                                    itemIcon = '💊'; 
                                    itemActionLabel = '服用';
                                    itemOnAction = (qty) => handleUsePill(item.id, qty);
                                } else if (item.category === 'materials') {
                                    const isHerb = HERB_DETAILS[item.id];
                                    itemIcon = isHerb ? '🌿' : '💎';
                                } else if (item.category === 'methods') {
                                    itemIcon = '📜'; 
                                    const isEquipped = detail ? (selectedMember.mainMethodId === detail.id || selectedMember.movementMethodId === detail.id || selectedMember.auxMethodIds.includes(detail.id)) : false;
                                    const meetsReq = detail && (detail.category === 'method') ? checkMethodRequirements(selectedMember, detail as unknown as CultivationMethod) : true;

                                    if (!isEquipped) {
                                        if (meetsReq) {
                                            itemActionLabel = '研习';
                                            itemOnAction = () => { toggleMethod(item.id, (detail as any).type); setFocusedBagItem(null); };
                                        } else {
                                            itemActionLabel = '条件不足';
                                            itemOnAction = undefined; // Button will show but do nothing or show warning
                                        }
                                    }
                                }

                                return renderBagItem(itemIcon, item.id, item.count, itemOnAction, itemActionLabel);
                            })}
                        </div>
                    ) : (
                        <div className="w-full py-24 text-center text-gray-700 italic border-2 border-dashed border-white/5 rounded-xl flex flex-col items-center gap-4">
                            <span className="text-5xl opacity-10">🎒</span>
                            <span>行囊中空空如也，或许该去外界游历一番</span>
                        </div>
                    )}
                </div>
            </div>
        );
    };

    return (
        <div className="bg-[#1e130c] border-l-4 border-yellow-800 h-full flex flex-col relative overflow-hidden font-serif shadow-2xl">
            {tooltip && tooltip.visible && (
                <div 
                    className="fixed z-[10000] pointer-events-none bg-black/95 border-2 border-yellow-900/50 p-4 rounded shadow-[0_10px_40px_rgba(0,0,0,0.8)] backdrop-blur-md animate-fade-in"
                    style={{ 
                        left: tooltip.x, 
                        top: tooltip.y, 
                        transform: `translate(-50%, ${tooltip.y > window.innerHeight / 2 ? '-100%' : '0'})` 
                    }}
                >
                    {tooltip.content}
                </div>
            )}

            <div className="p-4 border-b border-yellow-900/30 bg-black/40 shrink-0">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="text-xl font-cursive text-yellow-500">⛩️ 族谱常青</h2>
                    <span className="text-[10px] text-yellow-700 bg-black/50 px-3 py-1 rounded-full border border-yellow-900/20">
                        底蕴: {state.heritagePool}
                    </span>
                </div>
                <div className="grid grid-cols-2 gap-2 mb-4">
                    <div className="bg-[#2c1810]/50 p-2 rounded border border-yellow-900/20">
                        <p className="text-[9px] text-gray-500">家族灵石</p>
                        <p className="text-yellow-400 font-bold text-sm">✨ {state.spiritStones}</p>
                    </div>
                    <div className="bg-[#2c1810]/50 p-2 rounded border border-yellow-900/20">
                        <p className="text-[9px] text-gray-500">族人数量</p>
                        <p className="text-blue-400 font-bold text-sm">👥 {state.members.filter(m => m.status !== 'dead').length}</p>
                    </div>
                </div>
                <div className="flex p-1 bg-black/40 rounded-lg gap-1 border border-yellow-900/10">
                    <button onClick={() => handleTabChange('alive')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'alive' ? 'bg-yellow-800 text-yellow-100 shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>在世族人</button>
                    <button onClick={() => handleTabChange('deceased')} className={`flex-1 py-1.5 text-xs rounded transition-all ${activeTab === 'deceased' ? 'bg-gray-800 text-gray-100' : 'text-gray-500 hover:text-gray-400'}`}>英灵祠堂</button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto p-4 space-y-2 custom-scrollbar">
                {activeTab === 'alive' && (
                    <button onClick={onAddMember} className="w-full bg-green-900/20 hover:bg-green-800/40 text-green-400 border border-green-900/50 py-2 rounded text-xs transition-all flex items-center justify-center gap-2 mb-4 group">
                        <span>👶</span> 诞育麟儿
                    </button>
                )}
                {pagedMembers.length > 0 ? pagedMembers.map(m => {
                    const needsBreakthrough = isBreakthroughNeeded(m);
                    return (
                        <div 
                            key={m.id} onClick={() => activeTab === 'alive' && setSelectedMemberId(m.id)}
                            className={`group p-3 rounded-md border transition-all cursor-pointer animate-fade-in ${selectedMemberId === m.id ? 'bg-[#2d1e15] border-yellow-600 scale-[1.02] shadow-xl' : 'bg-[#1e130c] border-yellow-900/30 hover:border-yellow-700/50'}`}
                        >
                            <div className="flex justify-between items-start mb-1">
                                <div className="flex items-center gap-2">
                                    <span className="font-bold text-sm text-yellow-100/90">{m.name}</span>
                                    <span className="text-[8px] text-[#8c6b4f]">[{m.position}]</span>
                                    {m.assignment === 'Cultivation' && m.realm !== Realm.Mortal && <span className="text-[8px] animate-pulse text-blue-400">修炼中</span>}
                                    {needsBreakthrough && <span className="text-[8px] bg-red-900 text-white px-1 animate-bounce rounded-sm">瓶颈</span>}
                                </div>
                                <button className={`text-[9px] px-2 py-0.5 rounded border shadow-sm hover:brightness-125 transition-all ${getRealmStyle(m.realm)}`}>
                                    {getRealmText(m.realm, m.subRealm)}
                                </button>
                            </div>
                            <div className="flex justify-between text-[10px] text-gray-500 items-baseline">
                                <span>评级：<span className={`font-black ${getTierColor(m.tier)}`}>{m.tier}</span></span>
                                <span className={`text-[9px] opacity-80 italic font-sans ${getRootGradeColor(m.rootGrade)}`}>{m.rootGrade}</span>
                            </div>
                            {activeTab === 'alive' && m.realm !== Realm.Mortal && (
                                <div className="mt-2 w-full h-1 bg-black/40 rounded-full overflow-hidden border border-white/5">
                                    <div 
                                        className={`h-full transition-all duration-1000 ${needsBreakthrough ? 'bg-red-600 shadow-[0_0_8px_rgba(220,38,38,0.8)]' : 'bg-blue-500/60'}`} 
                                        style={{ width: `${m.cultivationProgress}%` }}
                                    ></div>
                                </div>
