    YuanYing = '元婴',
    YuanShen = '化神'
}

export enum Element {
    Gold = '金',
    Wood = '木',
    Water = '水',
    Fire = '火',
    Earth = '土'
}

export type TaskType = 'Cultivation' | 'Exploration' | 'Research' | 'Patrol' | 'Idle' | 'Mission';
export type TalentTier = '凡人' | '平庸' | '普通' | '超凡' | '天才' | '绝世' | '绝世天骄';
