                            <button 
                                onClick={(e) => { e.stopPropagation(); if (methodId !== null) toggleMethod(methodId, type); hideTooltip(); }}
                                className="bg-red-900/80 hover:bg-red-700 text-white text-[7px] py-0.5 px-1 rounded-full border border-red-500/50"
