                    <span className="text-[7px] sm:text-[8px] text-yellow-500/80 font-bold whitespace-nowrap">{label}</span>
                </div>
            </div>
        );
    };

    const renderEquipSlot = (itemId: number | null, label: string, icon: string, slotKey: keyof ClanMember['equippedItems']) => {
        const isFocused = focusedEquipSlot === slotKey;
        const isLeftSide = slotKey === 'weapon' || slotKey === 'armor';
        const itemDetails = itemId !== null ? ALL_ITEM_DETAILS[itemId] : null;
        const style = itemDetails ? getGradeStyle(itemDetails.grade) : null;

        return (
            <div className="flex flex-col items-center gap-1 relative">
                <div 
                    onClick={() => itemId !== null && setFocusedEquipSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => itemId !== null && showTooltip(e, renderItemTooltipContent(itemId))}
                    onMouseLeave={hideTooltip}
                    className={`w-12 h-12 sm:w-16 sm:h-16 rounded border-2 flex items-center justify-center transition-all cursor-pointer relative overflow-hidden 
                        ${itemDetails ? `${style?.border} ${style?.text} ${style?.glow} ${style?.bg} ${style?.hover} ${style?.dropShadow}` : 'bg-black/40 border-white/10 text-gray-800'}`}>
                    <span className="font-bold text-[10px] px-1 text-center leading-tight">
