    const renderBagItem = (icon: string, id: number, count: number, onAction?: (qty: number) => void, actionLabel?: string) => {
        const details = ALL_ITEM_DETAILS[id] as any;
        if (!details) return null;

        const style = getGradeStyle(details.grade);
        const isRestricted = details.requiredRealm && selectedMember?.realm !== details.requiredRealm;

        return (
            <div 
                key={id} 
                onClick={() => {
                    if (focusedBagItem === id) {
                        setFocusedBagItem(null);
                        setUseQuantity(1);
                    } else {
                        setFocusedBagItem(id);
                        setUseQuantity(1);
                    }
                }}
                onMouseEnter={(e) => showTooltip(e, renderItemTooltipContent(id))}
                onMouseLeave={hideTooltip}
                className={`${style.bg} border-2 ${style.border} ${style.glow} p-3 rounded-lg flex flex-col items-center group ${style.hover} transition-all aspect-[4/5] justify-between shadow-lg relative overflow-hidden ${isRestricted ? 'opacity-50 grayscale' : ''}`}>

