                                    <div className="flex items-center gap-1 mb-2 bg-black/60 p-1 rounded-md border border-white/5">
                                        <button 
                                            onClick={(e) => { e.stopPropagation(); setUseQuantity(Math.max(1, useQuantity - 1)); }}
                                            className="w-6 h-6 flex items-center justify-center bg-white/5 text-gray-400 rounded hover:bg-white/10 text-xs font-bold"
                                        >
                                            -
                                        </button>
                                        <input 
                                            type="number" 
                                            value={useQuantity} 
                                            onChange={(e) => setUseQuantity(Math.min(count, Math.max(1, parseInt(e.target.value) || 1)))}
