                                            onClick={(e) => { e.stopPropagation(); setUseQuantity(Math.min(count, useQuantity + 1)); }}
                                            className="w-6 h-6 flex items-center justify-center bg-white/5 text-gray-400 rounded hover:bg-white/10 text-xs font-bold"
                                        >
                                            +
                                        </button>
                                    </div>
                                )}
                                <button 
                                    onClick={(e) => { e.stopPropagation(); onAction(useQuantity); hideTooltip(); }}
                                    className={`text-white text-[11px] py-1.5 px-3 rounded font-bold shadow-lg w-full ${style.bg.replace('40', '80')} hover:brightness-125 border ${style.border}`}
                                >
                                    {actionLabel || '操作'} {useQuantity > 1 ? `x${useQuantity}` : ''}
                                </button>
                            </>
                        )}
                        <button 
                             onClick={(e) => { e.stopPropagation(); setFocusedBagItem(null); }}
                             className="mt-1 text-[9px] text-gray-500 hover:text-gray-300"
                        >
                            取消
                        </button>
                    </div>
                )}
