    const renderCultivationTab = () => {
        if (!selectedMember) return null;
        return (
            <div className="h-full flex flex-col min-h-0 overflow-hidden animate-fade-in">
                <div className="relative w-full flex-2 items-center justify-center py-4 sm:py-6 bg-black/10 rounded-xl border border-white/5 shadow-xl overflow-hidden mb-2">
                    <div className="absolute inset-0 pointer-events-none opacity-10 flex items-center justify-center">
                         <div className="w-[180px] h-[180px] sm:w-[240px] sm:h-[240px] border border-yellow-900/10 rounded-full animate-[spin_40s_linear_infinite]"></div>
                         <div className="absolute w-[140px] h-[140px] sm:w-[180px] sm:h-[180px] border border-yellow-700/5 rounded-full"></div>
                    </div>

                    <div className="relative grid grid-cols-3 gap-x-4 sm:gap-x-12 gap-y-2 sm:gap-y-4 z-10 items-center">
