                            {renderSlotItem(selectedMember.auxMethodIds[0] || null, 'Combat', '辅修I', 'aux0')}
                            {renderSlotItem(selectedMember.auxMethodIds[1] || null, 'Combat', '辅修II', 'aux1')}
