    };

    const renderRelationsTab = () => {
        if (!selectedMember) return null;

        const findMember = (id?: string | null) => state.members.find(m => m.id === id);

        const father = findMember(selectedMember.fatherId);
        const mother = findMember(selectedMember.motherId);
        const spouse = findMember(selectedMember.spouseId);
        const mentor = findMember(selectedMember.mentorId);

        const children = state.members.filter(m => m.fatherId === selectedMember.id || m.motherId === selectedMember.id);
        const siblings = state.members.filter(m => 
            m.id !== selectedMember.id && 
            (m.fatherId === selectedMember.fatherId && selectedMember.fatherId !== null) &&
            (m.motherId === selectedMember.motherId && selectedMember.motherId !== null)
        );
        const disciples = state.members.filter(m => m.mentorId === selectedMember.id);

        const MemberCard = ({ member: m, label, icon }: { member: ClanMember, label: string, icon: string }) => (
            <div 
                onClick={() => setSelectedMemberId(m.id)}
                className="bg-black/30 border border-yellow-900/20 p-3 rounded-lg flex items-center gap-3 hover:border-yellow-500/50 transition-all cursor-pointer group shadow-lg"
            >
                <div className="w-10 h-10 rounded-full bg-yellow-900/10 flex items-center justify-center border border-yellow-900/30 text-xl group-hover:scale-110 transition-transform">
                    {icon}
                </div>
                <div className="flex-1">
                    <div className="flex justify-between items-center">
                        <span className="text-xs font-bold text-yellow-100">{m.name}</span>
                        <span className="text-[8px] text-gray-500 bg-black/40 px-1.5 py-0.5 rounded border border-white/5">{label}</span>
                    </div>
                    <div className="flex justify-between items-center mt-1">
                        <span className={`text-[9px] ${getRealmStyle(m.realm).split(' ')[2]}`}>{getRealmText(m.realm, m.subRealm)}</span>
                        <span className={`text-[9px] font-black ${getTierColor(m.tier)}`}>{m.tier}</span>
                    </div>
                </div>
            </div>
        );

        const Section = ({ title, children: sectionChildren, icon }: { title: string, children: React.ReactNode, icon: string }) => (
            <div className="space-y-3">
                <h4 className="text-yellow-600 text-[12px] font-bold uppercase tracking-[0.2em] border-b border-yellow-900/10 pb-1 flex items-center gap-2">
                    <span>{icon}</span> {title}
                </h4>
                <div className="grid grid-cols-1 md:grid-cols-2 gap-3">
                    {sectionChildren}
                </div>
            </div>
        );

        return (
            <div className="h-full overflow-y-auto custom-scrollbar space-y-8 animate-fade-in pr-2 pt-2 pb-10">
                <div className="bg-black/20 p-4 rounded-xl border border-yellow-900/10 flex items-center justify-between">
                    <div>
                        <p className="text-xs text-gray-500">当前辈分</p>
                        <p className="text-2xl font-cursive text-yellow-500 mt-1">
                            {GENERATIONS[selectedMember.generation] || '通'} 字辈
                        </p>
                    </div>
                    <div className="text-right">
                        <p className="text-xs text-gray-500">家族地位</p>
                        <p className="text-sm font-bold text-orange-400 mt-1">{selectedMember.position}</p>
                    </div>
                </div>

                {(father || mother || spouse) && (
                    <Section title="至亲眷属" icon="💍">
                        {father && <MemberCard member={father} label="尊父" icon="👴" />}
                        {mother && <MemberCard member={mother} label="慈母" icon="👵" />}
                        {spouse && <MemberCard member={spouse} label="道侣" icon="💍" />}
                    </Section>
                )}

                {siblings.length > 0 && (
                    <Section title="同胞兄弟" icon="🤝">
                        {siblings.map(m => <MemberCard key={m.id} member={m} label="同胞" icon="🤝" />)}
                    </Section>
                )}

                {children.length > 0 && (
                    <Section title="膝下子女" icon="👶">
                        {children.map(m => <MemberCard key={m.id} member={m} label="子女" icon="👶" />)}
                    </Section>
                )}

                {(mentor || disciples.length > 0) && (
                    <Section title="宗门承传" icon="🎓">
                        {mentor && <MemberCard member={mentor} label="恩师" icon="🎓" />}
                        {disciples.map(m => <MemberCard key={m.id} member={m} label="门生" icon="✍️" />)}
                    </Section>
                )}
            </div>
        );
    };

    const sortedBagItems = useMemo(() => {
        if (!selectedMember) return [];
        const inv = selectedMember.personalInventory;

        const itemsList: Array<{ id: number; count: number; category: BagSubTab }> = [];

        const addItemsToList = (record: Record<number, number>, category: BagSubTab) => {
            Object.entries(record).forEach(([id, count]) => {
                if (count > 0) itemsList.push({ id: parseInt(id), count, category });
            });
        };

        if (bagSubTab === 'all' || bagSubTab === 'equipment') addItemsToList(inv.weapons, 'equipment');
        if (bagSubTab === 'all' || bagSubTab === 'pills') addItemsToList(inv.pills, 'pills');
        if (bagSubTab === 'all' || bagSubTab === 'materials') {
            addItemsToList(inv.herbs, 'materials');
            addItemsToList(inv.minerals, 'materials');
        }
        if (bagSubTab === 'all' || bagSubTab === 'methods') addItemsToList(inv.methods, 'methods');

        return itemsList.sort((a, b) => {
            const detailA = ALL_ITEM_DETAILS[a.id];
            const detailB = ALL_ITEM_DETAILS[b.id];
            if (!detailA || !detailB) return 0;

            if (bagSortKey === 'grade') {
                const gradeA = typeof detailA.grade === 'number' ? detailA.grade : (detailA.grade === '神器残片' ? 9 : 0);
                const gradeB = typeof detailB.grade === 'number' ? detailB.grade : (detailB.grade === '神器残片' ? 9 : 0);
                return gradeB - gradeA;
            } else if (bagSortKey === 'quantity') {
                return b.count - a.count;
            } else {
                return detailA.name.localeCompare(detailB.name, 'zh-CN');
            }
        });
    }, [selectedMember, bagSubTab, bagSortKey]);

    const renderBagTab = () => {
        if (!selectedMember) return null;
        return (
            <div className="h-full flex flex-col min-h-0 animate-fade-in pr-2 overflow-hidden">
                <div className="flex flex-wrap items-center justify-between gap-4 mb-4 shrink-0">
                    <div className="flex flex-wrap gap-2 p-1 bg-black/40 rounded-xl border border-yellow-900/20 w-fit">
                        <button onClick={() => setBagSubTab('all')} className={`px-3 sm:px-5 py-2 text-[10px] sm:text-xs rounded-lg transition-all font-bold ${bagSubTab === 'all' ? 'bg-yellow-700 text-white shadow-lg' : 'text-gray-500 hover:text-gray-300'}`}>📦 全部</button>
