import { Realm, ClanMember } from '../types';
import { REALM_ORDER, CULTIVATION_METHODS } from '../constants';

/**
 * 修炼系统配置与公式实现
 * 
 * 1、每一大境界内升级经验：ΔEXP(m, n) = BaseEXP(m) × r^(n-1)
 *    m：境界序号 (练气=1, 筑基=2...)
 *    n：层级 (1 → 2 为 n=1)
 *    r：境界内指数 (1.25)
 * 
 * 2、每一境界的首层基础经验：
 *    BaseEXP(m) = BaseEXP(m-1) × r^8 × C
 *    C：跨境界系数 (1.3)
 *    强限制：BaseEXP(练气) = 100
 */

const R_FACTOR = 1.25;
const C_FACTOR = 1.3;
const QI_BASE_EXP = 100;

/**
 * 获取大境界的基础经验值 BaseEXP(m)
 */
export const getBaseExpForRealm = (realmIndex: number): number => {
    if (realmIndex < 1) return 0; // 凡人
    if (realmIndex === 1) return QI_BASE_EXP; // 练气

    // 递归或循环计算：BaseEXP(m) = BaseEXP(1) * (r^8 * C)^(m-1)
    const realmJumpMultiplier = Math.pow(R_FACTOR, 8) * C_FACTOR;
    return QI_BASE_EXP * Math.pow(realmJumpMultiplier, realmIndex - 1);
};

/**
 * 获取当前层级升到下一级所需的绝对经验值 ΔEXP(m, n)
 * @param realmIndex 境界序号 (练气=1)
 * @param subRealm 当前层级 (1-9)
 */
export const getRequiredExp = (realmIndex: number, subRealm: number): number => {
    if (realmIndex < 1) return 100; // 凡人引气入体固定需求
    if (subRealm >= 9) return getBaseExpForRealm(realmIndex) * Math.pow(R_FACTOR, 8); // 9层满经验即为瓶颈

    const baseExp = getBaseExpForRealm(realmIndex);
    // n=1 时对应 subRealm=1，即 1->2 所需经验
    return baseExp * Math.pow(R_FACTOR, subRealm - 1);
};

/**
 * 计算成员每年的修炼产出（绝对修为点）
 * 1、baseGain(m) = 1.75 × [ ΔEXP(m,1) ]^0.6
 * 2、实际经验 = baseGain(m) × 灵根倍率 × 资质修正 × (1 + 功法修正)
 */
export const calculateYearlyExpGain = (member: ClanMember): number => {
    const realmIdx = REALM_ORDER.indexOf(member.realm);
    if (realmIdx < 1) return 0;

    // 1. 获取该境界 1->2 的经验需求 ΔEXP(m, 1)
    const deltaExpM1 = getRequiredExp(realmIdx, 1);

    // 2. 计算基础产出点数 baseGain
    const baseGain = 1.75 * Math.pow(deltaExpM1, 0.6);

    // 3. 灵根倍率影响：0.6 + 0.1 × (最高灵根值 - 1)
    // 假设灵根属性取成员灵根中的最高一项（符合玄鉴仙族中主灵根的概念）
    const maxRoot = Math.max(
        member.roots.gold,
        member.roots.wood,
        member.roots.water,
        member.roots.fire,
        member.roots.earth
    );
    const rootMultiplier = maxRoot > 0 ? (0.6 + 0.1 * (maxRoot - 1)) : 0.5;

    // 4. 资质修正：(1 + aptitude / (aptitude + 150))
    const aptitudeFactor = 1 + (member.aptitude / (member.aptitude + 150));

    // 5. 功法修正
    let methodBonus = 0;
    if (member.mainMethodId) {
        const method = CULTIVATION_METHODS.find(m => m.id === member.mainMethodId);
        if (method && method.buffs.cultivationSpeed) {
            methodBonus = method.buffs.cultivationSpeed / 100; // buffs.cultivationSpeed 存储为百分比，如 5 表示 5%
        }
    }

    // 最终计算实际经验点
    const actualExp = baseGain * rootMultiplier * aptitudeFactor * (1 + methodBonus);

    return actualExp;
};

/**
 * 计算成员每年的百分比进度增加值
 */
export const calculateYearlyProgress = (member: ClanMember): number => {
    if (member.realm === Realm.Mortal) return 0;

    const realmIdx = REALM_ORDER.indexOf(member.realm);
    const requiredExp = getRequiredExp(realmIdx, member.subRealm);
    const gainExp = calculateYearlyExpGain(member);

    // 返回增加的百分比 (0-100)
    return (gainExp / requiredExp) * 100;
};

