import React, { useState } from 'react';
import { GameState, ClanMember, Region, Realm, Building, Inventory } from './types';
import { INITIAL_MEMBERS, INITIAL_REGIONS, REALM_ORDER, BUILDING_TYPES, ALL_ITEM_DETAILS } from './constants';
import { CLAN_MASTER_REGISTRY } from './data/master_registry';
import ClanDashboard from './components/ClanDashboard';
import WorldMap from './components/WorldMap';
import ClanManagement from './components/ClanManagement';
import BreakthroughModal from './components/BreakthroughModal';
import { generateYearlyEvent } from './services/geminiService';
import { calculateYearlyProgress, getRequiredExp } from './components/CultivationSystem';

const App: React.FC = () => {
    const [state, setState] = useState<GameState>({
        year: 1,
        spiritStones: CLAN_MASTER_REGISTRY.spiritStones,
        merit: CLAN_MASTER_REGISTRY.merit,
        luck: CLAN_MASTER_REGISTRY.luck,
        members: INITIAL_MEMBERS,
        regions: INITIAL_REGIONS,
        buildings: [],
        inventory: CLAN_MASTER_REGISTRY.inventory,
        currentRegionId: '',
        isMirrorActive: false,
        logs: ["太平历初，望月李氏在此立基。昊天镜悬于祠堂，照破虚妄。"],
        heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
        unlockedPositions: ['家主', '弟子'],
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    // Breakthrough State
    const [breakingMemberId, setBreakingMemberId] = useState<string | null>(null);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let yearLogs: string[] = [];
            let updatedMembers = [...prev.members];

            // 查找并处理目标成员
            updatedMembers = updatedMembers.map(m => {
                if (m.id !== id) return m;

                let nm = { ...m, ...updates };

                // 实时处理灵力溢出晋升逻辑
                if (updates.cultivationProgress !== undefined && nm.realm !== Realm.Mortal) {
                    let progress = nm.cultivationProgress;
                    let subRealm = nm.subRealm;
                    const realmIdx = REALM_ORDER.indexOf(nm.realm);

                    // 循环检测是否满足晋升条件（支持连跳）
                    let currentReq = getRequiredExp(realmIdx, subRealm);
                    while (progress >= currentReq && subRealm < 9) {
                        progress -= currentReq;
                        subRealm += 1;
                        currentReq = getRequiredExp(realmIdx, subRealm);
                        yearLogs.push(`【${prev.year}载·晋升】${nm.name} 气息升华，实时突破至 ${nm.realm} ${subRealm}层。`);
                    }

                    // 达到 9 层后的封顶处理
                    if (subRealm === 9 && progress >= currentReq) {
                        progress = currentReq; // 经验值封顶为当前所需
                        // 仅在首次达到巅峰时记录
                        if (m.subRealm < 9 || m.cultivationProgress < currentReq) {
                            yearLogs.push(`【${prev.year}载·瓶颈】${nm.name} 触碰天门，已达 ${nm.realm} 巅峰之境。`);
                        }
                    }

                    nm.cultivationProgress = progress;
                    nm.subRealm = subRealm;
                }

                return nm;
            });

            // 处理职位的排他性
            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '弟子' } : m
                );
            }

            return {
                ...prev,
                members: updatedMembers,
                logs: yearLogs.length > 0 ? [...yearLogs, ...prev.logs].slice(0, 30) : prev.logs
            };
        });
    };

    const handleUnlockPosition = (posName: string, cost: number) => {
        if (state.merit < cost) return;
        setState(prev => ({
            ...prev,
            merit: prev.merit - cost,
            unlockedPositions: [...prev.unlockedPositions, posName],
            logs: [`【${prev.year}载·职位】册封权限已开启：${posName}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleUpdateBuilding = (id: string, updates: Partial<Building>) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => b.id === id ? { ...b, ...updates } : b)
        }));
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (state.spiritStones < info.baseCost) return;

        const newBuilding: Building = {
            id: `b_${Date.now()}`,
            type,
            level: 1,
            assignedMemberId: null,
            isFinished: false,
            turnsRemaining: info.baseTurns
        };

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, newBuilding],
            logs: [`【${prev.year}载·营建】家族开始营造 ${info.name}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleAssignBuilding = (buildingId: string, memberId: string | null) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => {
                if (b.id === buildingId) {
                    return { ...b, assignedMemberId: memberId };
                }
                if (memberId !== null && b.assignedMemberId === memberId) {
                    return { ...b, assignedMemberId: null };
                }
                return b;
            })
        }));
    };

    const handleNextYear = async () => {
        setIsProcessing(true);
        let yearLogs: string[] = [];
        let stoneGain = 50; 
        let meritGain = 2;
        let bonusInventory: Inventory = { herbs: {}, minerals: {}, paper: 0, pills: {}, weapons: {}, methods: {}, scrolls: {} };

        const currentYear = state.year;

        const updatedBuildings = state.buildings.map(b => {
            let nb = { ...b };
            if (!nb.isFinished) {
                const remaining = nb.turnsRemaining - 1;
                if (remaining <= 0) {
                    yearLogs.push(`【${currentYear}载·营建】${BUILDING_TYPES[nb.type].name} 顺利落成。`);
                    nb = { ...nb, isFinished: true, turnsRemaining: 0 };
                } else {
                    nb = { ...nb, turnsRemaining: remaining };
                }
            } else {
                if (nb.activeProduction) {
                    const rem = nb.activeProduction.turnsRemaining - 1;
                    if (rem <= 0) {
                        const { recipeId, type } = nb.activeProduction;
                        const recipeName = ALL_ITEM_DETAILS[recipeId]?.name || '未知产物';
                        yearLogs.push(`【${currentYear}载·产出】${BUILDING_TYPES[nb.type].name} 完成了 ${recipeName} 的制作。`);

                        if (type === 'Alchemy') {
                            bonusInventory.pills[recipeId] = (bonusInventory.pills[recipeId] || 0) + 1;
                        } else {
                            bonusInventory.weapons[recipeId] = (bonusInventory.weapons[recipeId] || 0) + 1;
                        }

                        nb.activeProduction = undefined;
                    } else {
                        nb.activeProduction = { ...nb.activeProduction, turnsRemaining: rem };
                    }
                }
            }

            if (nb.isFinished) {
                if (nb.type === 'Market' && nb.assignedMemberId) stoneGain += 200;
                if (nb.type === 'SpiritField') {
                    bonusInventory.herbs[1300] = (bonusInventory.herbs[1300] || 0) + 5; // 灵谷草 ID: 1300
                }
            }
            return nb;
        });

        const memberStatusChanges: Record<string, Partial<ClanMember>> = {};

        const updatedRegions = state.regions.map(r => {
            let nr = { ...r };

            if (nr.owner === '望月李氏' && nr.production) {
                if (nr.production.stones) stoneGain += nr.production.stones;
                if (nr.production.merit) meritGain += nr.production.merit;
                if (nr.production.items) {
                    Object.entries(nr.production.items).forEach(([idStr, count]) => {
                        const id = parseInt(idStr);
                        if (nr.type === 'field') bonusInventory.herbs[id] = (bonusInventory.herbs[id] || 0) + count;
                        else if (nr.type === 'mine') bonusInventory.minerals[id] = (bonusInventory.minerals[id] || 0) + count;
                    });
                }
            }

            if (nr.activeMission) {
                const rem = nr.activeMission.turnsRemaining - 1;
                if (rem <= 0) {
                    const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                    if (member) {
                        const mType = nr.activeMission.type;
                        const memberPower = REALM_ORDER.indexOf(member.realm) * 10 + member.subRealm;
                        const diff = nr.difficulty;

                        let riskSuccess = true;
                        if (memberPower < diff) {
                            const riskFactor = (diff - memberPower) / 10; 
                            const roll = Math.random();
                            if (roll < riskFactor * 0.2) {
                                memberStatusChanges[member.id] = { status: 'dead', deathYear: currentYear };
                                yearLogs.push(`【${currentYear}载·讣闻】${member.name} 在 ${nr.name} 不幸陨落。`);
                                riskSuccess = false;
                            } else if (roll < riskFactor * 0.8) {
                                memberStatusChanges[member.id] = { status: 'injured' };
                                yearLogs.push(`【${currentYear}载·伤情】${member.name} 在 ${nr.name} 受了重伤。`);
                                riskSuccess = false;
                            }
                        }

                        if (riskSuccess) {
                            if (mType === 'Occupy' || mType === 'War') {
                                nr.owner = '望月李氏';
                                yearLogs.push(`【${currentYear}载·版图】${member.name} 平定了 ${nr.name}。`);
                            } else {
                                const rewardPool = nr.resources;
                                const rewardName = rewardPool[Math.floor(Math.random() * rewardPool.length)];
                                yearLogs.push(`【${currentYear}载·探查】${member.name} 在 ${nr.name} 寻得 ${rewardName}。`);
                                const foundItem = Object.values(ALL_ITEM_DETAILS).find(item => item.name === rewardName);
                                if (foundItem) {
                                    bonusInventory.minerals[foundItem.id] = (bonusInventory.minerals[foundItem.id] || 0) + 1;
                                }
                            }
                        }
                    }
                    nr.activeMission = undefined;
                } else {
                    nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                }
            }
            return nr;
        });

        const updatedMembers = state.members.map(m => {
            let nm = { ...m, ...(memberStatusChanges[m.id] || {}) };
            if (nm.status === 'dead') return nm;

            nm.age += 1;
            const hasRoots = (Object.values(nm.roots) as number[]).some(v => v > 0);

            if (nm.assignment === 'Cultivation' && hasRoots && nm.realm !== Realm.Mortal && nm.status === 'healthy') {
                // 增加绝对经验值
                const gain = calculateYearlyProgress(nm);
                let newProgress = nm.cultivationProgress + gain;
                let finalSubRealm = nm.subRealm;
                const realmIdx = REALM_ORDER.indexOf(nm.realm);

                // 循环处理层级突破（使用动态经验阈值）
                let currentReq = getRequiredExp(realmIdx, finalSubRealm);
                while (newProgress >= currentReq && finalSubRealm < 9) {
                    newProgress -= currentReq;
                    finalSubRealm += 1;
                    currentReq = getRequiredExp(realmIdx, finalSubRealm);
                    yearLogs.push(`【${currentYear}载·晋升】${nm.name} 突破至 ${nm.realm} ${finalSubRealm}层。`);
                }

                // 9层封顶瓶颈处理
                if (finalSubRealm === 9 && newProgress >= currentReq) {
                    newProgress = currentReq;
                    if (nm.subRealm < 9 || nm.cultivationProgress < currentReq) {
                        yearLogs.push(`【${currentYear}载·瓶颈】${nm.name} 已达 ${nm.realm} 巅峰。`);
                    }
                }

                nm.cultivationProgress = newProgress;
                nm.subRealm = finalSubRealm;
            }

            if (nm.age >= nm.maxAge) {
                nm.status = 'dead'; nm.deathYear = currentYear;
                yearLogs.push(`【${currentYear}载·陨落】${nm.name} 寿元耗尽，溘然长逝。`);
            }

            if (nm.assignment === 'Mission') {
                const missionRegion = updatedRegions.find(r => r.activeMission?.memberId === nm.id);
                if (!missionRegion) nm.assignment = 'Idle';
            }

            if (nm.status === 'injured' && nm.assignment === 'Idle') {
                if (Math.random() > 0.5) {
                    nm.status = 'healthy';
                    yearLogs.push(`【${currentYear}载·痊愈】${nm.name} 伤势痊愈。`);
                }
            }

            return nm;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers, regions: updatedRegions });

        setState(prev => {
            const finalHerbs = { ...prev.inventory.herbs };
            Object.entries(bonusInventory.herbs).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalHerbs[id] = (finalHerbs[id] || 0) + count; 
            });
            const finalMinerals = { ...prev.inventory.minerals };
            Object.entries(bonusInventory.minerals).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalMinerals[id] = (finalMinerals[id] || 0) + count; 
            });
            const finalPills = { ...prev.inventory.pills };
            Object.entries(bonusInventory.pills).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalPills[id] = (finalPills[id] || 0) + count; 
            });
            const finalWeapons = { ...prev.inventory.weapons };
            Object.entries(bonusInventory.weapons).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalWeapons[id] = (finalWeapons[id] || 0) + count; 
            });

            return {
                ...prev,
                year: prev.year + 1,
                members: updatedMembers,
                buildings: updatedBuildings,
                regions: updatedRegions,
                spiritStones: prev.spiritStones + stoneGain,
                merit: prev.merit + meritGain,
                inventory: { 
                    ...prev.inventory, 
                    herbs: finalHerbs, 
                    minerals: finalMinerals,
                    pills: finalPills,
                    weapons: finalWeapons
                },
                logs: [...yearLogs, ...prev.logs].slice(0, 30)
            };
        });
        setEvent(newEvent);
        setIsProcessing(false);
    };

    const handleChoice = (choiceKey: 'choiceA' | 'choiceB') => {
        if (!event) return;

        const impact = event.impact;
        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones + (impact.spiritStones || 0),
            merit: prev.merit + (impact.merit || 0),
            luck: prev.luck + (impact.luck || 0),
            logs: [impact.log || `【${prev.year}载·因果】处理了：${event.title}`, ...prev.logs].slice(0, 30)
        }));
        setEvent(null);
    };

    const handleBreakthroughAttempt = (memberId: string, success: boolean) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;

            let updatedMembers = [...prev.members];
            let newLog = '';

            if (success) {
                const currentRealmIdx = REALM_ORDER.indexOf(member.realm);
                const nextRealm = REALM_ORDER[currentRealmIdx + 1] || Realm.YuanShen;
                newLog = `【${prev.year}载·突破】${member.name} 突破至 ${nextRealm}。`;

                updatedMembers = updatedMembers.map(m => m.id === memberId ? {
                    ...m,
                    realm: nextRealm,
                    subRealm: 1,
                    cultivationProgress: 0,
                    maxAge: m.maxAge + 100, 
                    legacyPoints: (m.legacyPoints || 0) + 10
                } : m);
            } else {
                newLog = `【${prev.year}载·突破】${member.name}破镜失败，修为跌落。`;
                updatedMembers = updatedMembers.map(m => m.id === memberId ? {
                    ...m,
                    subRealm: 8,
                    cultivationProgress: 0,
                    status: 'injured'
                } : m);
            }

            return {
                ...prev,
                members: updatedMembers,
                heritagePool: success ? prev.heritagePool + 10 : prev.heritagePool,
                logs: [newLog, ...prev.logs].slice(0, 30)
            };
        });
        setBreakingMemberId(null);
    };

    const handleUseHaotianMirror = () => {
        if (state.merit < 20) return;
        const undiscovered = state.regions.filter(r => !r.isDiscovered);
        if (undiscovered.length === 0) return;
        const reveal = undiscovered[Math.floor(Math.random() * undiscovered.length)];
        setState(prev => ({
            ...prev,
            merit: prev.merit - 20,
            regions: prev.regions.map(r => r.id === reveal.id ? { ...r, isDiscovered: true } : r),
            logs: [`【${prev.year}载·昊天镜】镜光照破了 ${reveal.name}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') {
            setIsManagementVisible(true);
            setState(p => ({ ...p, currentRegionId: '' }));
        } else {
            setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
        }
    };

    return (
        <div className="h-full w-full flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl shrink-0">
                <div className="flex items-center gap-12">
                    <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">族中功德</span>
                            <span className="text-lg font-mono text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year}</span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={handleUseHaotianMirror} disabled={state.merit < 20} className="px-5 py-2 bg-gradient-to-r from-blue-900 to-indigo-900 border border-blue-400 text-blue-100 rounded-full text-xs font-bold hover:brightness-125 transition-all shadow-[0_0_15px_rgba(59,130,246,0.4)] disabled:opacity-30">🪞 昊天镜 (20功德)</button>
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>📜 族谱</button>
                    <button onClick={handleNextYear} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">{isProcessing ? '推演中' : '岁过一载'}</button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />

                    <div className={`absolute bottom-6 left-6 transition-all duration-500 parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 flex flex-col overflow-hidden ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-64'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5 shrink-0 cursor-pointer" onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}>
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button className="text-[#4a3728] hover:text-black transition-transform duration-300" style={{ transform: isConsoleCollapsed ? 'rotate(180deg)' : 'rotate(0deg)' }}>▼</button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {state.logs.length > 0 ? state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold text-[11px] border-b border-[#4a3728]/5 pb-1 animate-fade-in">
                                        <span className="text-[#8b0000] mr-2">◈</span> {log}
                                    </p>
                                )) : (
                                    <p className="text-gray-500 italic text-[10px] text-center py-10">暂无家族记载</p>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                {isDashboardVisible && (
                    <div className="w-80 h-full border-l border-yellow-900/50 flex flex-col shrink-0">
                        <ClanDashboard 
                            state={state} 
                            onUpdateMember={handleUpdateMember} 
                            onAddMember={() => {}} 
                            onOpenBreakthrough={(id) => setBreakingMemberId(id)}
                        />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onUpdateBuilding={handleUpdateBuilding}
                    onAddBuilding={handleAddBuilding} 
                    onAssignBuilding={handleAssignBuilding} 
                    onClose={() => setIsManagementVisible(false)} 
                    onUnlockPosition={handleUnlockPosition}
                />
            )}

            {event && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-[#f4e4bc] w-full max-w-2xl p-8 rounded border-[12px] border-[#4a3728] shadow-2xl relative animate-scale-in">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 py-3 rounded-b-xl font-cursive text-2xl">{event.title}</div>
                        <div className="text-[#2c1810] leading-relaxed text-lg font-serif italic mb-8 max-h-[40vh] overflow-y-auto custom-scrollbar pr-4">{event.content}</div>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => handleChoice('choiceA')} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceA.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => handleChoice('choiceB')} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceB.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {breakingMemberId && (
                <BreakthroughModal 
                    member={state.members.find(m => m.id === breakingMemberId)!}
                    onClose={() => setBreakingMemberId(null)}
                    onAttempt={(success) => handleBreakthroughAttempt(breakingMemberId, success)}
                />
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo, useCallback } from 'react';
import { GameState, ClanMember, Realm, TaskType, DevelopmentPlan, CultivationMethod, MethodType, TalentTier, RootGrade, SpecializedTalents } from '../types';
import { 
    TASK_INFO, REALM_ORDER, DEVELOPMENT_PLANS, CULTIVATION_METHODS, 
    PHYSIQUE_DETAILS, ABILITY_DETAILS, getArtisanTitle, getArtisanBonus, 
    getWeaponMasteryTitle, getWeaponTalentBonus, 
    PILL_DETAILS, HERB_DETAILS, 
    GENERATIONS, ALL_ITEM_DETAILS
} from '../constants';
import { getRequiredExp } from './CultivationSystem';

/**
 * 根据品级获取对应的UI样式
 * 1-2品为白色；3品浅绿色、4品为深绿色；5品浅蓝色、6品为深蓝色；7品为紫色、8品为橙色、9品为红色
 */
const getGradeStyle = (grade: number | string | undefined) => {
    const g = typeof grade === 'number' ? grade : (grade === '神器残片' ? 9 : 0);

    // 1-2品：白色
    if (g <= 2) return {
        border: 'border-slate-300/60',
        text: 'text-slate-100',
        bg: 'bg-slate-900/60',
        hover: 'hover:border-slate-100',
        glow: 'shadow-[inset_0_0_10px_rgba(255,255,255,0.05)]',
        dropShadow: 'shadow-[0_0_5px_rgba(255,255,255,0.1)]'
    };
    // 3品：浅绿色
    if (g === 3) return {
        border: 'border-emerald-400/70',
        text: 'text-emerald-300',
        bg: 'bg-emerald-950/40',
        hover: 'hover:border-emerald-300',
        glow: 'shadow-[inset_0_0_12px_rgba(52,211,153,0.1)]',
        dropShadow: 'shadow-[0_0_8px_rgba(52,211,153,0.2)]'
    };
    // 4品：深绿色
    if (g === 4) return {
        border: 'border-green-700/80',
        text: 'text-green-400',
        bg: 'bg-green-950/50',
        hover: 'hover:border-green-500',
        glow: 'shadow-[inset_0_0_15px_rgba(21,128,61,0.15)]',
        dropShadow: 'shadow-[0_0_10px_rgba(21,128,61,0.3)]'
    };
    // 5品：浅蓝色
    if (g === 5) return {
        border: 'border-sky-400/80',
        text: 'text-sky-300',
        bg: 'bg-sky-950/40',
        hover: 'hover:border-sky-200',
        glow: 'shadow-[inset_0_0_15px_rgba(56,189,248,0.2)]',
        dropShadow: 'shadow-[0_0_12px_rgba(56,189,248,0.3)]'
    };
    // 6品：深蓝色
    if (g === 6) return {
        border: 'border-blue-700/90',
        text: 'text-blue-400',
        bg: 'bg-blue-950/50',
        hover: 'hover:border-blue-500',
        glow: 'shadow-[inset_0_0_18px_rgba(29,78,216,0.25)]',
        dropShadow: 'shadow-[0_0_15px_rgba(29,78,216,0.4)]'
    };
    // 7品：紫色
    if (g === 7) return {
        border: 'border-purple-600',
        text: 'text-purple-400',
        bg: 'bg-purple-950/40',
        hover: 'hover:border-purple-300',
        glow: 'shadow-[inset_0_0_20px_rgba(168,85,247,0.3)]',
        dropShadow: 'shadow-[0_0_18px_rgba(168,85,247,0.5)]'
    };
    // 8品：橙色
    if (g === 8) return {
        border: 'border-orange-500',
        text: 'text-orange-400',
        bg: 'bg-orange-950/40',
        hover: 'hover:border-orange-300',
        glow: 'shadow-[inset_0_0_22px_rgba(249,115,22,0.35)]',
        dropShadow: 'shadow-[0_0_20px_rgba(249,115,22,0.6)]'
    };
    // 9品：红色
    return {
        border: 'border-red-600',
        text: 'text-red-500',
        bg: 'bg-red-950/50',
        hover: 'hover:border-red-400',
        glow: 'shadow-[inset_0_0_25px_rgba(220,38,38,0.4)]',
        dropShadow: 'shadow-[0_0_25px_rgba(239,68,68,0.7)]'
    };
};

const getGradeColor = (grade: number | string | undefined) => {
    const style = getGradeStyle(grade);
    return `${style.border} ${style.text} ${style.dropShadow}`;
};

const getTierColor = (tier: TalentTier) => {
    switch (tier) {
        case '凡人': return 'text-slate-400';
        case '平庸': return 'text-gray-300';
        case '普通': return 'text-emerald-500';
        case '超凡': return 'text-sky-500';
        case '天才': return 'text-purple-500';
        case '绝世': return 'text-amber-500 shadow-[0_0_8px_rgba(245,158,11,0.4)]';
        case '绝世天骄': return 'text-rose-500 animate-pulse font-black shadow-[0_0_12px_rgba(244,63,94,0.6)]';
        default: return 'text-gray-400';
    }
};

const getTitleColor = (tier: TalentTier) => {
    switch (tier) {
        case '凡人': return 'text-white';
        case '平庸': return 'text-green-500';
        case '普通': return 'text-blue-400';
        case '超凡': return 'text-purple-500';
        case '天才': return 'text-orange-500';
        case '绝世': return 'text-amber-400';
        case '绝世天骄': return 'text-red-600';
        default: return 'text-white';
    }
};

const getRootGradeColor = (grade: RootGrade) => {
    switch (grade) {
        case '凡人': return 'text-slate-500';
        case '伪灵根': return 'text-gray-400';
        case '下品灵根': return 'text-emerald-600';
        case '中品灵根': return 'text-sky-600';
        case '上品灵根': return 'text-purple-600';
        case '极品灵根': return 'text-amber-600 font-bold';
        default: return 'text-gray-400';
    }
};

const getRealmStyle = (realm: Realm) => {
    if (realm === Realm.Mortal) return "border-[#4a3728] bg-[#2c1810] text-[#8c6b4f]";
    return "border-[#6b4e31] bg-[#3d2b1f] text-[#c9a063]";
};

const getRealmText = (realm: Realm, subRealm: number) => {
    if (realm === Realm.Mortal) return '凡人';
    return `${realm}${subRealm}层`;
};

const getGradeText = (method: CultivationMethod) => {
    const numerals = ['','一','二','三','四','五','六','七','八','九'];
    return `${numerals[method.grade]}品${method.quality}`;
};

const getElementColorClass = (key: string, val: number) => {
    if (val === 0) return 'text-gray-600 border-gray-800 opacity-30';
    switch (key) {
        case 'gold': return 'text-yellow-400 border-yellow-500 bg-yellow-500/10';
        case 'wood': return 'text-green-400 border-green-500 bg-green-500/10';
        case 'water': return 'text-blue-400 border-blue-500 bg-blue-500/10';
        case 'fire': return 'text-red-400 border-red-500 bg-red-500/10';
        case 'earth': return 'text-orange-700 border-orange-800 bg-orange-800/10';
        default: return 'text-gray-400 border-gray-500';
    }
};

const getElementName = (key: string) => {
    switch (key) {
        case 'gold': return '金';
        case 'wood': return '木';
        case 'water': return '水';
        case 'fire': return '火';
        case 'earth': return '土';
        default: return key;
    }
};

interface Props {
    state: GameState;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onAddMember: () => void;
    onOpenBreakthrough?: (id: string) => void;
}

const ITEMS_PER_PAGE = 8;
type BagSubTab = 'all' | 'equipment' | 'pills' | 'materials' | 'methods';
type SortKey = 'grade' | 'quantity' | 'name';

const ClanDashboard: React.FC<Props> = ({ state, onUpdateMember, onAddMember, onOpenBreakthrough }) => {
    const [selectedMemberId, setSelectedMemberId] = useState<string | null>(null);
    const [activeTab, setActiveTab] = useState<'alive' | 'deceased'>('alive');
    const [currentPage, setCurrentPage] = useState(0);
    const [detailTab, setDetailTab] = useState<'attr' | 'talents' | 'tasks' | 'cultivation' | 'plan' | 'bag' | 'relations'>('attr');
    const [bagSubTab, setBagSubTab] = useState<BagSubTab>('all');
    const [bagSortKey, setBagSortKey] = useState<SortKey>('grade');

    const [focusedSlot, setFocusedSlot] = useState<string | null>(null);
    const [focusedEquipSlot, setFocusedEquipSlot] = useState<string | null>(null);
    const [focusedBagItem, setFocusedBagItem] = useState<number | null>(null);
    const [useQuantity, setUseQuantity] = useState<number>(1);
    const [libraryType, setLibraryType] = useState<MethodType>('Cultivation');

    // Tooltip State
    const [tooltip, setTooltip] = useState<{
        content: React.ReactNode;
        x: number;
        y: number;
        visible: boolean;
    } | null>(null);

    const selectedMember = useMemo(() => 
        state.members.find(m => m.id === selectedMemberId), 
    [state.members, selectedMemberId]);

    const filteredMembers = useMemo(() => {
        const list = state.members.filter(m => activeTab === 'alive' ? m.status !== 'dead' : m.status === 'dead');
        return list.sort((a, b) => {
            if (activeTab === 'alive') {
                const realmDiff = REALM_ORDER.indexOf(b.realm) - REALM_ORDER.indexOf(a.realm);
                if (realmDiff !== 0) return realmDiff;
                return b.subRealm - a.subRealm;
            }
            return (b.deathYear || 0) - (a.deathYear || 0);
        });
    }, [state.members, activeTab]);

    const pagedMembers = filteredMembers.slice(currentPage * ITEMS_PER_PAGE, (currentPage + 1) * ITEMS_PER_PAGE);

    const handleTabChange = (tab: 'alive' | 'deceased') => {
        setActiveTab(tab);
        setCurrentPage(0);
        setSelectedMemberId(null);
    };

    const isBreakthroughNeeded = (member: ClanMember) => {
        const realmIdx = REALM_ORDER.indexOf(member.realm);
        const req = getRequiredExp(realmIdx, member.subRealm);
        return member.subRealm === 9 && member.cultivationProgress >= req && member.realm !== Realm.YuanShen;
    };

    const toggleMethod = (methodId: number, type: MethodType) => {
        if (!selectedMember) return;

        // Check requirements before allowing study
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        if (method) {
            const meetsReq = checkMethodRequirements(selectedMember, method);
            if (!meetsReq) {
                // Here we could show a visual warning, but for now we just return
                return;
            }
        }

        if (type === 'Cultivation') {
            onUpdateMember(selectedMember.id, { mainMethodId: selectedMember.mainMethodId === methodId ? null : methodId });
        } else if (type === 'Movement') {
            onUpdateMember(selectedMember.id, { movementMethodId: selectedMember.movementMethodId === methodId ? null : methodId });
        } else if (type === 'Combat') {
            const currentAux = selectedMember.auxMethodIds;
            if (currentAux.includes(methodId)) {
                onUpdateMember(selectedMember.id, { auxMethodIds: currentAux.filter(mid => mid !== methodId) });
            } else if (currentAux.length < 4) {
                onUpdateMember(selectedMember.id, { auxMethodIds: [...currentAux, methodId] });
            }
        }
        setFocusedSlot(null);
    };

    const checkMethodRequirements = (member: ClanMember, method: CultivationMethod) => {
        const req = method.requirements;
        if (!req) return true;

        // Realm check
        if (req.realm) {
            if (REALM_ORDER.indexOf(member.realm) < REALM_ORDER.indexOf(req.realm)) return false;
        }

        // Roots check
        if (req.minRoots) {
            for (const [key, val] of Object.entries(req.minRoots)) {
                if ((member.roots as any)[key] < (val || 0)) return false;
            }
        }

        // Root Grade check
        if (req.minRootGrade) {
            const grades: RootGrade[] = ['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'];
            if (grades.indexOf(member.rootGrade) < grades.indexOf(req.minRootGrade)) return false;
        }

        return true;
    };

    const libraryMethods = useMemo(() => {
        if (!selectedMember) return [];
        return CULTIVATION_METHODS.filter(m => {
            if (m.type !== libraryType) return false;
            const isOwnedByClan = (state.inventory.methods[m.id] || 0) > 0;
            const isOwnedBySelf = (selectedMember.personalInventory.methods[m.id] || 0) > 0;
            const isEquipped = selectedMember.mainMethodId === m.id || 
                             selectedMember.movementMethodId === m.id || 
                             selectedMember.auxMethodIds.includes(m.id);
            return isOwnedByClan || isOwnedBySelf || isEquipped;
        }).map(m => {
            const totalCount = (state.inventory.methods[m.id] || 0) + (selectedMember.personalInventory.methods[m.id] || 0);
            return { ...m, totalCount };
        });
    }, [libraryType, selectedMember, state.inventory.methods]);

    const showTooltip = useCallback((e: React.MouseEvent, content: React.ReactNode) => {
        const rect = e.currentTarget.getBoundingClientRect();
        let x = rect.left + rect.width / 2;
        let y = rect.top;

        if (rect.top < 300) {
            y = rect.bottom + 12;
        } else {
            y = rect.top - 12;
        }

        const tooltipWidth = 260;
        if (x - tooltipWidth / 2 < 20) x = tooltipWidth / 2 + 20;
        if (x + tooltipWidth / 2 > window.innerWidth - 20) x = window.innerWidth - tooltipWidth / 2 - 20;

        setTooltip({ content, x, y, visible: true });
    }, []);

    const hideTooltip = useCallback(() => {
        setTooltip(prev => prev ? { ...prev, visible: false } : null);
    }, []);

    const renderMethodTooltipContent = (method: CultivationMethod) => {
        const req = method.requirements;
        const meetsRealm = !req?.realm || REALM_ORDER.indexOf(selectedMember?.realm || Realm.Mortal) >= REALM_ORDER.indexOf(req.realm);

        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{method.name}</span>
                    <span className={`text-[10px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(method.grade)}`}>
                        {getGradeText(method)}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-2 leading-relaxed italic">{method.desc}</p>

                {/* Requirements Section */}
                <div className="mb-3 p-1.5 bg-black/30 border border-yellow-900/10 rounded">
                    <p className="text-[10px] text-orange-400 font-bold mb-1">【修炼要求】</p>
                    {req?.realm && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">境界要求</span>
                            <span className={meetsRealm ? 'text-green-500' : 'text-red-500'}>{req.realm}</span>
                        </div>
                    )}
                    {req?.minRootGrade && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">灵根等级</span>
                            <span className={`text-right ${selectedMember && (['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'].indexOf(selectedMember.rootGrade) >= ['凡人', '伪灵根', '下品灵根', '中品灵根', '上品灵根', '极品灵根'].indexOf(req.minRootGrade)) ? 'text-gray-300' : 'text-red-500'}`}>{req.minRootGrade}</span>
                        </div>
                    )}
                    {req?.minRoots && Object.entries(req.minRoots).map(([key, val]) => {
                        const memberVal = selectedMember ? (selectedMember.roots as any)[key] : 0;
                        const meetsVal = memberVal >= (val || 0);
                        return (
                            <div key={key} className="flex justify-between text-[10px]">
                                <span className="text-gray-500">{getElementName(key)}灵根</span>
                                <span className={`text-right ${meetsVal ? 'text-gray-300' : 'text-red-500'}`}>≥ {val}</span>
                            </div>
                        );
                    })}
                    {!req?.realm && !req?.minRoots && !req?.minRootGrade && (
                        <p className="text-[9px] text-gray-600">无特殊要求</p>
                    )}
                </div>

                <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                    <p className="text-[10px] text-green-500 font-bold mb-1">【功法效果】</p>
                    {method.buffs.cultivationSpeed && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">修炼速度</span>
                            <span className={method.buffs.cultivationSpeed > 0 ? 'text-green-400' : 'text-red-400'}>
                                {method.buffs.cultivationSpeed > 0 ? '+' : ''}{method.buffs.cultivationSpeed}%
                            </span>
                        </div>
                    )}
                    {method.buffs.attack && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">战斗力</span>
                            <span className="text-orange-400">+{method.buffs.attack}%</span>
                        </div>
                    )}
                    {method.buffs.defense && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">防御力</span>
                            <span className="text-blue-400">+{method.buffs.defense}%</span>
                        </div>
                    )}
                    {method.buffs.maxAge && (
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">延寿</span>
                            <span className="text-emerald-400">+{method.buffs.maxAge} 载</span>
                        </div>
                    )}
                    <p className="text-[9px] text-yellow-600/80 mt-2 italic">"{method.bonus}"</p>
                </div>
            </div>
        );
    };

    const renderItemTooltipContent = (itemId: number) => {
        const details = ALL_ITEM_DETAILS[itemId];

        if (!details) return (
            <div className="w-52 sm:w-64 font-serif border-2 border-red-900/30 p-2 bg-black/40">
                <span className="text-gray-500 text-xs">未知物品 ID：{itemId}</span>
            </div>
        );

        // 如果是功法，直接复用功法专用的详细提示信息
        if (details.category === 'method') {
            return renderMethodTooltipContent(details as unknown as CultivationMethod);
        }

        const gradeStr = (details as any).gradeText || (details.grade !== undefined ? (typeof details.grade === 'number' ? `${details.grade}品` : details.grade) : '凡物');

        return (
            <div className="w-52 sm:w-64 font-serif">
                <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                    <span className="text-yellow-500 font-bold text-sm">{details.name}</span>
                    <span className={`text-[9px] px-1.5 py-0.5 rounded-sm font-bold border ${getGradeColor(details.grade)}`}>
                        {gradeStr}
                    </span>
                </div>
                <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{details.desc}</p>

                {(details as any).requiredRealm && (
                    <div className="mb-2 p-1.5 bg-black/30 border border-yellow-900/20 rounded">
                        <span className="text-[10px] text-gray-400">使用要求：</span>
                        <span className={`text-[10px] font-bold ${selectedMember?.realm === (details as any).requiredRealm ? 'text-green-500' : 'text-red-500'}`}>
                            {(details as any).requiredRealm}
                        </span>
                    </div>
                )}

                {(details as any).effect && (
                    <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                        <p className="text-[10px] text-orange-400 font-bold mb-1">【物品效果】</p>
                        <div className="flex justify-between text-[10px]">
                            <span className="text-gray-500">效果描述</span>
                            <span className="text-gray-200">{(details as any).effect}</span>
                        </div>
                    </div>
                )}
            </div>
        );
    };

    const handleUnequip = (slot: keyof ClanMember['equippedItems']) => {
        if (!selectedMember) return;
        const itemId = selectedMember.equippedItems[slot];
        if (itemId === null) return;

        const newEquipped = { ...selectedMember.equippedItems, [slot]: null };
        const newInventory = { ...selectedMember.personalInventory };

        newInventory.weapons[itemId] = (newInventory.weapons[itemId] || 0) + 1;

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedEquipSlot(null);
    };

    const handleEquip = (itemId: number, category: 'weapon' | 'armor' | 'accessory' | 'treasure') => {
        if (!selectedMember) return;

        const newEquipped = { ...selectedMember.equippedItems };
        const newInventory = { ...selectedMember.personalInventory };

        const currentItemId = newEquipped[category];
        if (currentItemId !== null) {
            newInventory.weapons[currentItemId] = (newInventory.weapons[currentItemId] || 0) + 1;
        }

        if (newInventory.weapons[itemId] > 0) {
            newInventory.weapons[itemId]--;
            if (newInventory.weapons[itemId] === 0) delete newInventory.weapons[itemId];
        }

        newEquipped[category] = itemId;

        onUpdateMember(selectedMember.id, { 
            equippedItems: newEquipped,
            personalInventory: newInventory
        });
        setFocusedBagItem(null);
    };

    const handleUsePill = (pillId: number, quantity: number) => {
        if (!selectedMember) return;

        const pillData = PILL_DETAILS[pillId] as any;
        if (!pillData) return;

        if (pillData.requiredRealm && selectedMember.realm !== pillData.requiredRealm) {
            setFocusedBagItem(null);
            hideTooltip();
            return;
        }

        const newInventory = { ...selectedMember.personalInventory };
        const currentCount = newInventory.pills[pillId] || 0;
        if (currentCount < quantity) return;

        newInventory.pills[pillId] -= quantity;
        if (newInventory.pills[pillId] === 0) delete newInventory.pills[pillId];

        const updates: Partial<ClanMember> = { personalInventory: newInventory };

        const pillEffects = pillData.effects;
        if (pillEffects) {
            if (pillEffects.cultivationProgress) {
                updates.cultivationProgress = (selectedMember.cultivationProgress || 0) + (pillEffects.cultivationProgress * quantity);
            }
            if (pillEffects.status) {
                updates.status = pillEffects.status;
            }
            if (pillEffects.maxAge) {
                updates.maxAge = (selectedMember.maxAge || 0) + (pillEffects.maxAge * quantity);
            }
            if (pillEffects.divineSense) {
                updates.divineSense = (selectedMember.divineSense || 0) + (pillEffects.divineSense * quantity);
            }
        }

        onUpdateMember(selectedMember.id, updates);
        setFocusedBagItem(null);
        setUseQuantity(1);
        hideTooltip();
    };

    const renderPhysiqueTooltipContent = (physique: string) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-pink-400 font-bold text-sm">{physique}</span>
                <span className="text-[9px] px-1.5 py-0.5 rounded-sm font-bold border border-pink-900/50 text-pink-500">天赋体质</span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{PHYSIQUE_DETAILS[physique] || '暂无详细记载。'}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-pink-500 font-bold mb-1">【先天禀赋】</p>
                <div className="flex justify-between text-[10px]">
                    <span className="text-gray-500">觉醒状态</span>
                    <span className="text-emerald-400">已圆满</span>
                </div>
            </div>
        </div>
    );

    const renderAbilityTooltipContent = (ability: string) => (
        <div className="w-52 sm:w-64 font-serif">
            <div className="flex justify-between items-center mb-2 border-b border-yellow-900/20 pb-2">
                <span className="text-orange-400 font-bold text-sm">{ability}</span>
                <span className="text-[9px] px-1.5 py-0.5 rounded-sm font-bold border border-orange-900/50 text-orange-500">神通秘术</span>
            </div>
            <p className="text-[10px] sm:text-xs text-gray-200 mb-4 leading-relaxed italic">{ABILITY_DETAILS[ability] || '暂无详细记载。'}</p>
            <div className="space-y-1.5 pt-1 border-t border-yellow-900/10">
                <p className="text-[10px] text-orange-500 font-bold mb-1">【神通威力】</p>
                <div className="flex justify-between text-[10px]">
                    <span className="text-gray-500">威能评价</span>
                    <span className="text-orange-300">莫测</span>
                </div>
            </div>
        </div>
    );

    const renderNamePlaque = (member: ClanMember) => (
        <div className={`border-2 border-black bg-red-950/60 px-6 py-2 shadow-[0_4px_20px_rgba(0,0,0,0.6)] backdrop-blur-sm ${member.tier === '绝世天骄' ? 'ring-1 ring-red-500/50' : ''}`}>
            <h2 className="text-xl sm:text-2xl lg:text-3xl font-cursive tracking-wider text-center whitespace-nowrap">
                <span className="text-yellow-400">{member.name}</span>
                {member.title && (
                    <>
                        <span className="mx-1 text-black font-bold">·</span>
                        <span className={`${getTitleColor(member.tier)}`}>{member.title}</span>
                    </>
                )}
            </h2>
        </div>
    );

    const renderSlotItem = (methodId: number | null, type: MethodType, label: string, slotKey: string) => {
        const method = CULTIVATION_METHODS.find(m => m.id === methodId);
        const isFocused = focusedSlot === slotKey;
        const style = method ? getGradeStyle(method.grade) : null;

        return (
            <div className="flex flex-col items-center gap-1 group relative">
                <div 
                    onClick={() => methodId !== null && setFocusedSlot(isFocused ? null : slotKey)}
                    onMouseEnter={(e) => method && showTooltip(e, renderMethodTooltipContent(method))}
                    onMouseLeave={hideTooltip}
                    className={`relative cursor-pointer transition-all duration-300 rounded-md border-2 flex items-center justify-center 
