                >
                    {method ? (
                        <div className={`w-full h-full p-1 flex flex-col items-center justify-center text-center font-bold ${style?.text}`}>
                             <span className="text-base sm:text-lg opacity-80 leading-none">📜</span>
                             <span className="text-[7px] sm:text-[8px] leading-tight line-clamp-2 mt-0.5">{method.name}</span>
