                                >
                                    {actionLabel || '操作'} {useQuantity > 1 ? `x${useQuantity}` : ''}
                                </button>
                            </>
                        )}
                        <button 
                             onClick={(e) => { e.stopPropagation(); setFocusedBagItem(null); }}
                             className="mt-1 text-[9px] text-gray-500 hover:text-gray-300"
                        >
                            取消
                        </button>
                    </div>
                )}
