import { GoogleGenAI, Type } from "@google/genai";
import { GameState, ClanMember } from "../types";

const SEASON_NAMES = ['', '春', '夏', '秋', '冬'];

export async function generateYearlyEvent(state: GameState) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const aliveMembers = state.members.filter(m => m.status === 'healthy');
    const memberSummary = aliveMembers.map(m => `${m.name}(${m.realm}${m.subRealm}层)`).join(', ');

    const prompt = `
        你是一个修仙题材的叙事大师，风格参考小说《玄鉴仙族》。
        当前游戏时间：太平历 第${state.year}年 ${SEASON_NAMES[state.season]}季。
        家族背景：望月李氏。
        家族成员：${memberSummary}。
        当前资源：灵石${state.spiritStones}，功德${state.merit}。

        请根据当前季节和家族状态，生成本季度发生的一件随机事件。
        春：万物复苏、灵药萌发、新生儿、势力外交。
        夏：烈日炎炎、火系灵气爆发、冲突、邪修出没。
        秋：收获季节、散修集会、洞府开启、境界突破。
        冬：寒冬腊月、资源紧缺、妖兽下山、老祖悟道。

        要求返回JSON格式，描述要简洁且富有修仙韵味。
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt,
            config: {
                responseMimeType: "application/json",
                responseSchema: {
                    type: Type.OBJECT,
                    properties: {
                        title: { type: Type.STRING, description: '事件名称' },
                        content: { type: Type.STRING, description: '详细的叙事文字' },
                        choiceA: {
                            type: Type.OBJECT,
                            properties: {
                                text: { type: Type.STRING },
                                effect: { type: Type.STRING }
                            },
                            required: ["text", "effect"]
                        },
                        choiceB: {
                            type: Type.OBJECT,
                            properties: {
                                text: { type: Type.STRING },
                                effect: { type: Type.STRING }
                            },
                            required: ["text", "effect"]
                        },
                        impact: {
                            type: Type.OBJECT,
                            properties: {
                                spiritStones: { type: Type.NUMBER },
                                merit: { type: Type.NUMBER },
                                luck: { type: Type.NUMBER },
                                log: { type: Type.STRING }
                            },
                            required: ["spiritStones", "merit", "luck", "log"]
                        }
                    },
                    required: ["title", "content", "choiceA", "choiceB", "impact"]
                }
            }
        });
        return JSON.parse(response.text.trim());
    } catch (error) {
        console.error("Gemini Error:", error);
        return null;
    }
}

export async function consultHaotianMirror(state: GameState, query: string) {
    const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
    const prompt = `
        你是昊天镜的镜灵。玩家作为李氏老祖正在向你请教。
        当前家族处境：${JSON.stringify(state.members)}。
        玩家提问：${query}。

        请以高深莫测、看透因果的语气回答，给出战略性的建议或揭示一段未来的碎片。
    `;

    try {
        const response = await ai.models.generateContent({
            model: 'gemini-3-flash-preview',
            contents: prompt
        });
        return response.text;
    } catch (error) {
        return "镜面模糊，似有天机遮掩...";
    }
}

import { Realm, ClanMember, Element } from '../types';
import { REALM_ORDER, CULTIVATION_METHODS } from '../constants';

/**
 * 修炼系统配置与公式实现
 */

const R_FACTOR = 1.25;
const C_FACTOR = 1.3;
const QI_BASE_EXP = 100;

/**
 * 获取大境界的基础经验值 BaseEXP(m)
 */
export const getBaseExpForRealm = (realmIndex: number): number => {
    if (realmIndex < 1) return 0; // 凡人
    if (realmIndex === 1) return QI_BASE_EXP; // 练气

    const realmJumpMultiplier = Math.pow(R_FACTOR, 8) * C_FACTOR;
    return QI_BASE_EXP * Math.pow(realmJumpMultiplier, realmIndex - 1);
};

/**
 * 获取当前层级升到下一级所需的绝对经验值 ΔEXP(m, n)
 */
export const getRequiredExp = (realmIndex: number, subRealm: number): number => {
    if (realmIndex < 1) return 100; 
    if (subRealm >= 9) return getBaseExpForRealm(realmIndex) * Math.pow(R_FACTOR, 8); 

    const baseExp = getBaseExpForRealm(realmIndex);
    return baseExp * Math.pow(R_FACTOR, subRealm - 1);
};

/**
 * 计算成员每年的修炼产出（绝对修为点）
 */
export const calculateYearlyExpGain = (member: ClanMember): number => {
    const realmIdx = REALM_ORDER.indexOf(member.realm);
    if (realmIdx < 1) return 0;

    const deltaExpM1 = getRequiredExp(realmIdx, 1);
    const baseGain = 1.75 * Math.pow(deltaExpM1, 0.6);

    let rootValue = 0;
    const mainMethod = CULTIVATION_METHODS.find(m => m.id === member.mainMethodId);

    if (mainMethod && mainMethod.element !== '无') {
        const elementMap: Record<string, keyof typeof member.roots> = {
            [Element.Gold]: 'gold',
            [Element.Wood]: 'wood',
            [Element.Water]: 'water',
            [Element.Fire]: 'fire',
            [Element.Earth]: 'earth'
        };
        const key = elementMap[mainMethod.element as string];
        rootValue = member.roots[key];
    } else {
        rootValue = Math.max(
            member.roots.gold,
            member.roots.wood,
            member.roots.water,
            member.roots.fire,
            member.roots.earth
        );
    }

    const rootMultiplier = rootValue > 0 ? (0.6 + 0.1 * (rootValue - 1)) : 0.5;
    const aptitudeFactor = 1 + (member.aptitude / (member.aptitude + 150));

    let methodBonus = 0;
    if (mainMethod && mainMethod.buffs.cultivationSpeed) {
        methodBonus = mainMethod.buffs.cultivationSpeed / 100;
    }

    const actualExp = baseGain * rootMultiplier * aptitudeFactor * (1 + methodBonus);
    return actualExp;
};

/**
 * 计算成员每季（每回合）的修为增加值
 */
export const calculateSeasonalProgress = (member: ClanMember): number => {
    if (member.realm === Realm.Mortal) return 0;
    // 将年进度除以 4，实现每回合结算一次
    return calculateYearlyExpGain(member) / 4;
};

/**
 * 保留原函数作为兼容或参考
 */
export const calculateYearlyProgress = (member: ClanMember): number => {
    return calculateYearlyExpGain(member);
};

