        heritagePool: CLAN_MASTER_REGISTRY.heritagePool,
        unlockedPositions: ['家主', '弟子'],
    });

    const [event, setEvent] = useState<any>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const [isDashboardVisible, setIsDashboardVisible] = useState(true);
    const [isManagementVisible, setIsManagementVisible] = useState(false);
    const [isConsoleCollapsed, setIsConsoleCollapsed] = useState(false);

    const [breakingMemberId, setBreakingMemberId] = useState<string | null>(null);

    const handleUpdateMember = (id: string, updates: Partial<ClanMember>) => {
        setState(prev => {
            let yearLogs: string[] = [];
            let updatedMembers = [...prev.members];

            updatedMembers = updatedMembers.map(m => {
                if (m.id !== id) return m;

                let nm = { ...m, ...updates };

                if (updates.cultivationProgress !== undefined && nm.realm !== Realm.Mortal) {
                    let progress = nm.cultivationProgress;
                    let subRealm = nm.subRealm;
                    const realmIdx = REALM_ORDER.indexOf(nm.realm);

                    let currentReq = getRequiredExp(realmIdx, subRealm);
                    while (progress >= currentReq && subRealm < 9) {
                        progress -= currentReq;
                        subRealm += 1;
                        currentReq = getRequiredExp(realmIdx, subRealm);
                        yearLogs.push(`【${prev.year}载·晋升】${nm.name} 气息升华，实时突破至 ${nm.realm} ${subRealm}层。`);
                    }

                    if (subRealm === 9 && progress >= currentReq) {
                        progress = currentReq;
                        if (m.subRealm < 9 || m.cultivationProgress < currentReq) {
                            yearLogs.push(`【${prev.year}载·瓶颈】${nm.name} 触碰天门，已达 ${nm.realm} 巅峰之境。`);
                        }
                    }

                    nm.cultivationProgress = progress;
                    nm.subRealm = subRealm;
                }

                return nm;
            });

            if (updates.position === '家主') {
                updatedMembers = updatedMembers.map(m => 
                    (m.position === '家主' && m.id !== id) ? { ...m, position: '弟子' } : m
                );
            }

            return {
                ...prev,
                members: updatedMembers,
                logs: yearLogs.length > 0 ? [...yearLogs, ...prev.logs].slice(0, 30) : prev.logs
            };
        });
    };

    const handleUnlockPosition = (posName: string, cost: number) => {
        if (state.merit < cost) return;
        setState(prev => ({
            ...prev,
            merit: prev.merit - cost,
            unlockedPositions: [...prev.unlockedPositions, posName],
            logs: [`【${prev.year}载·职位】册封权限已开启：${posName}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleUpdateBuilding = (id: string, updates: Partial<Building>) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => b.id === id ? { ...b, ...updates } : b)
        }));
    };

    const handleAddBuilding = (type: string) => {
        const info = BUILDING_TYPES[type];
        if (state.spiritStones < info.baseCost) return;

        const newBuilding: Building = {
            id: `b_${Date.now()}`,
            type,
            level: 1,
            assignedMemberId: null,
            isFinished: false,
            turnsRemaining: info.baseTurns
        };

        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones - info.baseCost,
            buildings: [...prev.buildings, newBuilding],
            logs: [`【${prev.year}载·营建】家族开始营造 ${info.name}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleAssignBuilding = (buildingId: string, memberId: string | null) => {
        setState(prev => ({
            ...prev,
            buildings: prev.buildings.map(b => {
                if (b.id === buildingId) {
                    return { ...b, assignedMemberId: memberId };
                }
                if (memberId !== null && b.assignedMemberId === memberId) {
                    return { ...b, assignedMemberId: null };
                }
                return b;
            })
        }));
    };

    const handleNextTurn = async () => {
        setIsProcessing(true);
        let turnLogs: string[] = [];
        let stoneGain = 50; 
        let meritGain = 2;
        let bonusInventory: Inventory = { herbs: {}, minerals: {}, paper: 0, pills: {}, weapons: {}, methods: {}, scrolls: {} };

        const currentYear = state.year;
        const currentSeason = state.season;
        const nextSeason = currentSeason >= 4 ? 1 : currentSeason + 1;
        const isYearIncrement = currentSeason === 4;
        const seasonTag = SEASON_NAMES[currentSeason];

        // 1. 建筑与产出结算 (每季结算)
        const updatedBuildings = state.buildings.map(b => {
            let nb = { ...b };
            if (!nb.isFinished) {
                const remaining = nb.turnsRemaining - 1;
                if (remaining <= 0) {
                    turnLogs.push(`【${currentYear}载·${seasonTag}】${BUILDING_TYPES[nb.type].name} 顺利落成。`);
                    nb = { ...nb, isFinished: true, turnsRemaining: 0 };
                } else {
                    nb = { ...nb, turnsRemaining: remaining };
                }
            } else {
                if (nb.activeProduction) {
                    const rem = nb.activeProduction.turnsRemaining - 1;
                    if (rem <= 0) {
                        const { recipeId, type } = nb.activeProduction;
                        const recipeName = ALL_ITEM_DETAILS[recipeId]?.name || '未知产物';
                        turnLogs.push(`【${currentYear}载·${seasonTag}】${BUILDING_TYPES[nb.type].name} 完成了 ${recipeName} 的制作。`);

                        if (type === 'Alchemy') {
                            bonusInventory.pills[recipeId] = (bonusInventory.pills[recipeId] || 0) + 1;
                        } else {
                            bonusInventory.weapons[recipeId] = (bonusInventory.weapons[recipeId] || 0) + 1;
                        }

                        nb.activeProduction = undefined;
                    } else {
                        nb.activeProduction = { ...nb.activeProduction, turnsRemaining: rem };
                    }
                }
            }

            if (nb.isFinished) {
                if (nb.type === 'Market' && nb.assignedMemberId) stoneGain += 200;
                if (nb.type === 'SpiritField') {
                    bonusInventory.herbs[1300] = (bonusInventory.herbs[1300] || 0) + 5;
                }
            }
            return nb;
        });

        // 2. 地区与任务结算 (每季结算)
        const memberStatusChanges: Record<string, Partial<ClanMember>> = {};
        const updatedRegions = state.regions.map(r => {
            let nr = { ...r };

            if (nr.owner === '望月李氏' && nr.production) {
                if (nr.production.stones) stoneGain += nr.production.stones;
                if (nr.production.merit) meritGain += nr.production.merit;
                if (nr.production.items) {
                    Object.entries(nr.production.items).forEach(([idStr, count]) => {
                        const id = parseInt(idStr);
                        if (nr.type === 'field') bonusInventory.herbs[id] = (bonusInventory.herbs[id] || 0) + count;
                        else if (nr.type === 'mine') bonusInventory.minerals[id] = (bonusInventory.minerals[id] || 0) + count;
                    });
                }
            }

            if (nr.activeMission) {
                const rem = nr.activeMission.turnsRemaining - 1;
                if (rem <= 0) {
                    const member = state.members.find(m => m.id === nr.activeMission!.memberId);
                    if (member) {
                        const mType = nr.activeMission.type;
                        const memberPower = REALM_ORDER.indexOf(member.realm) * 10 + member.subRealm;
                        const diff = nr.difficulty;

                        let riskSuccess = true;
                        if (memberPower < diff) {
                            const riskFactor = (diff - memberPower) / 10; 
                            const roll = Math.random();
                            if (roll < riskFactor * 0.2) {
                                memberStatusChanges[member.id] = { status: 'dead', deathYear: currentYear };
                                turnLogs.push(`【${currentYear}载·讣闻】${member.name} 在 ${nr.name} 不幸陨落。`);
                                riskSuccess = false;
                            } else if (roll < riskFactor * 0.8) {
                                memberStatusChanges[member.id] = { status: 'injured' };
                                turnLogs.push(`【${currentYear}载·伤情】${member.name} 在 ${nr.name} 受了重伤。`);
                                riskSuccess = false;
                            }
                        }

                        if (riskSuccess) {
                            if (mType === 'Occupy' || mType === 'War') {
                                nr.owner = '望月李氏';
                                turnLogs.push(`【${currentYear}载·版图】${member.name} 平定了 ${nr.name}。`);
                            } else {
                                const rewardPool = nr.resources;
                                const rewardName = rewardPool[Math.floor(Math.random() * rewardPool.length)];
                                turnLogs.push(`【${currentYear}载·探查】${member.name} 在 ${nr.name} 寻得 ${rewardName}。`);
                                const foundItem = Object.values(ALL_ITEM_DETAILS).find(item => item.name === rewardName);
                                if (foundItem) {
                                    bonusInventory.minerals[foundItem.id] = (bonusInventory.minerals[foundItem.id] || 0) + 1;
                                }
                            }
                        }
                    }
                    nr.activeMission = undefined;
                } else {
                    nr.activeMission = { ...nr.activeMission, turnsRemaining: rem };
                }
            }
            return nr;
        });

        // 3. 成员结算 (修炼每季结算，寿命每年结算)
        const updatedMembers = state.members.map(m => {
            let nm = { ...m, ...(memberStatusChanges[m.id] || {}) };
            if (nm.status === 'dead') return nm;

            // 寿命仅在冬去春来时增加
            if (isYearIncrement) {
                nm.age += 1;
                if (nm.age >= nm.maxAge) {
                    nm.status = 'dead'; nm.deathYear = currentYear;
                    turnLogs.push(`【${currentYear}载·岁末】${nm.name} 寿元耗尽，溘然长逝。`);
                }
            }

            // 修炼结算：每回合（每季）进行一次
            const hasRoots = (Object.values(nm.roots) as number[]).some(v => v > 0);
            if (nm.assignment === 'Cultivation' && hasRoots && nm.realm !== Realm.Mortal && nm.status === 'healthy') {
                const gain = calculateSeasonalProgress(nm);
                let newProgress = nm.cultivationProgress + gain;
                let finalSubRealm = nm.subRealm;
                const realmIdx = REALM_ORDER.indexOf(nm.realm);

                let currentReq = getRequiredExp(realmIdx, finalSubRealm);
                while (newProgress >= currentReq && finalSubRealm < 9) {
                    newProgress -= currentReq;
                    finalSubRealm += 1;
                    currentReq = getRequiredExp(realmIdx, finalSubRealm);
                    turnLogs.push(`【${currentYear}载·${seasonTag}】${nm.name} 突破至 ${nm.realm} ${finalSubRealm}层。`);
                }

                if (finalSubRealm === 9 && newProgress >= currentReq) {
                    newProgress = currentReq;
                    if (nm.subRealm < 9 || nm.cultivationProgress < currentReq) {
                        turnLogs.push(`【${currentYear}载·${seasonTag}】${nm.name} 已达 ${nm.realm} 巅峰。`);
                    }
                }

                nm.cultivationProgress = newProgress;
                nm.subRealm = finalSubRealm;
            }

            if (nm.assignment === 'Mission') {
                const missionRegion = updatedRegions.find(r => r.activeMission?.memberId === nm.id);
                if (!missionRegion) nm.assignment = 'Idle';
            }

            if (nm.status === 'injured' && nm.assignment === 'Idle') {
                if (Math.random() > 0.5) {
                    nm.status = 'healthy';
                    turnLogs.push(`【${currentYear}载·${seasonTag}】${nm.name} 伤势痊愈。`);
                }
            }

            return nm;
        });

        const newEvent = await generateYearlyEvent({ ...state, members: updatedMembers, regions: updatedRegions });

        setState(prev => {
            const finalHerbs = { ...prev.inventory.herbs };
            Object.entries(bonusInventory.herbs).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalHerbs[id] = (finalHerbs[id] || 0) + count; 
            });
            const finalMinerals = { ...prev.inventory.minerals };
            Object.entries(bonusInventory.minerals).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalMinerals[id] = (finalMinerals[id] || 0) + count; 
            });
            const finalPills = { ...prev.inventory.pills };
            Object.entries(bonusInventory.pills).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalPills[id] = (finalPills[id] || 0) + count; 
            });
            const finalWeapons = { ...prev.inventory.weapons };
            Object.entries(bonusInventory.weapons).forEach(([idStr, count]) => { 
                const id = parseInt(idStr);
                finalWeapons[id] = (finalWeapons[id] || 0) + count; 
            });

            return {
                ...prev,
                year: isYearIncrement ? prev.year + 1 : prev.year,
                season: nextSeason,
                members: updatedMembers,
                buildings: updatedBuildings,
                regions: updatedRegions,
                spiritStones: prev.spiritStones + stoneGain,
                merit: prev.merit + meritGain,
                inventory: { 
                    ...prev.inventory, 
                    herbs: finalHerbs, 
                    minerals: finalMinerals,
                    pills: finalPills,
                    weapons: finalWeapons
                },
                logs: [...turnLogs, ...prev.logs].slice(0, 30)
            };
        });
        setEvent(newEvent);
        setIsProcessing(false);
    };

    const handleChoice = (choiceKey: 'choiceA' | 'choiceB') => {
        if (!event) return;
        const impact = event.impact as any;
        setState(prev => ({
            ...prev,
            spiritStones: prev.spiritStones + (impact.spiritStones || 0),
            merit: prev.merit + (impact.merit || 0),
            luck: prev.luck + (impact.luck || 0),
            logs: [impact.log || `【${prev.year}载·因果】处理了：${event.title}`, ...prev.logs].slice(0, 30)
        }));
        setEvent(null);
    };

    const handleBreakthroughAttempt = (memberId: string, success: boolean) => {
        setState(prev => {
            const member = prev.members.find(m => m.id === memberId);
            if (!member) return prev;

            let updatedMembers = [...prev.members];
            let newLog = '';

            if (success) {
                const currentRealmIdx = REALM_ORDER.indexOf(member.realm);
                const nextRealm = REALM_ORDER[currentRealmIdx + 1] || Realm.YuanShen;
                newLog = `【${prev.year}载·突破】${member.name} 突破至 ${nextRealm}。`;

                updatedMembers = updatedMembers.map(m => m.id === memberId ? {
                    ...m,
                    realm: nextRealm,
                    subRealm: 1,
                    cultivationProgress: 0,
                    maxAge: m.maxAge + 100, 
                    legacyPoints: (m.legacyPoints || 0) + 10
                } : m);
            } else {
                newLog = `【${prev.year}载·突破】${member.name}破镜失败，修为跌落。`;
                updatedMembers = updatedMembers.map(m => m.id === memberId ? {
                    ...m,
                    subRealm: 8,
                    cultivationProgress: 0,
                    status: 'injured'
                } : m);
            }

            return {
                ...prev,
                members: updatedMembers,
                heritagePool: success ? prev.heritagePool + 10 : prev.heritagePool,
                logs: [newLog, ...prev.logs].slice(0, 30)
            };
        });
        setBreakingMemberId(null);
    };

    const handleUseHaotianMirror = () => {
        if (state.merit < 20) return;
        const undiscovered = state.regions.filter(r => !r.isDiscovered);
        if (undiscovered.length === 0) return;
        const reveal = undiscovered[Math.floor(Math.random() * undiscovered.length)];
        setState(prev => ({
            ...prev,
            merit: prev.merit - 20,
            regions: prev.regions.map(r => r.id === reveal.id ? { ...r, isDiscovered: true } : r),
            logs: [`【${prev.year}载·昊天镜】镜光照破了 ${reveal.name}。`, ...prev.logs].slice(0, 30)
        }));
    };

    const handleSelectRegion = (r: Region | null) => {
        if (r && r.id === 'li_clan_home') {
            setIsManagementVisible(true);
            setState(p => ({ ...p, currentRegionId: '' }));
        } else {
            setState(p => ({ ...p, currentRegionId: r ? r.id : '' }));
        }
    };

    return (
        <div className="h-full w-full flex flex-col bg-[#0f0a07] text-gray-300 overflow-hidden select-none font-serif">
            <header className="h-16 bg-[#2c1810] border-b-2 border-yellow-900/50 flex items-center justify-between px-8 z-40 shadow-xl shrink-0">
                <div className="flex items-center gap-12">
                    <h1 className="text-2xl font-cursive text-yellow-500 tracking-widest">玄鉴仙族：昊天纪元</h1>
                    <div className="flex gap-6 items-center border-l border-yellow-900/30 pl-8">
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">家族灵石</span>
                            <span className="text-lg font-mono text-yellow-400">✨ {state.spiritStones}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">族中功德</span>
                            <span className="text-lg font-mono text-blue-400">💠 {state.merit}</span>
                        </div>
                        <div className="flex flex-col">
                            <span className="text-[10px] text-gray-500 uppercase">天罡历载</span>
                            <span className="text-lg font-mono text-yellow-100">{state.year} · <span className="text-yellow-500">{SEASON_NAMES[state.season]}</span></span>
                        </div>
                    </div>
                </div>
                <div className="flex items-center gap-4">
                    <button onClick={handleUseHaotianMirror} disabled={state.merit < 20} className="px-5 py-2 bg-gradient-to-r from-blue-900 to-indigo-900 border border-blue-400 text-blue-100 rounded-full text-xs font-bold hover:brightness-125 transition-all shadow-[0_0_15px_rgba(59,130,246,0.4)] disabled:opacity-30">🪞 昊天镜 (20功德)</button>
                    <button onClick={() => setIsManagementVisible(true)} className="px-5 py-2 bg-black/40 border border-orange-900 text-orange-500 rounded-full text-xs font-bold hover:bg-orange-900/20 transition-all">🏛️ 家族管理</button>
                    <button onClick={() => setIsDashboardVisible(!isDashboardVisible)} className={`px-5 py-2 rounded-full border transition-all text-xs font-bold ${isDashboardVisible ? 'bg-yellow-800 border-yellow-500 text-yellow-100' : 'bg-black/40 border-yellow-900 text-gray-500'}`}>📜 族谱</button>
                    <button onClick={handleNextTurn} disabled={isProcessing || !!event} className="bg-gradient-to-b from-yellow-700 to-yellow-900 hover:from-yellow-600 hover:to-yellow-800 disabled:opacity-30 text-white px-8 py-2 rounded border-t border-yellow-500/30 border-b-4 border-black/50 font-bold transition-all text-sm shadow-lg">{isProcessing ? '推演中' : '岁时轮转'}</button>
                </div>
            </header>

            <main className="flex-1 flex overflow-hidden relative">
                <div className="flex-1 relative bg-[#0a0705]">
                    <WorldMap 
                        regions={state.regions} 
                        members={state.members} 
                        currentRegionId={state.currentRegionId} 
                        onSelectRegion={handleSelectRegion} 
                        onUpdateMember={handleUpdateMember} 
                        onUpdateRegion={(id, u) => setState(p => ({ ...p, regions: p.regions.map(r => r.id === id ? { ...r, ...u } : r) }))} 
                    />

                    <div className={`absolute bottom-6 left-6 transition-all duration-500 parchment border-2 border-[#4a3728] rounded-sm shadow-2xl z-20 opacity-95 flex flex-col overflow-hidden ${isConsoleCollapsed ? 'w-48 h-10' : 'w-72 h-64'}`}>
                        <div className="flex justify-between items-center px-4 py-2 border-b border-[#4a3728]/30 bg-black/5 shrink-0 cursor-pointer" onClick={() => setIsConsoleCollapsed(!isConsoleCollapsed)}>
                            <span className="text-[11px] text-[#2c1810] font-bold uppercase tracking-widest font-cursive">族史摘要</span>
                            <button className="text-[#4a3728] hover:text-black transition-transform duration-300" style={{ transform: isConsoleCollapsed ? 'rotate(180deg)' : 'rotate(0deg)' }}>▼</button>
                        </div>
                        {!isConsoleCollapsed && (
                            <div className="flex-1 overflow-y-auto p-4 space-y-3 custom-scrollbar">
                                {state.logs.length > 0 ? state.logs.map((log, i) => (
                                    <p key={i} className="leading-relaxed text-black/80 font-serif font-bold text-[11px] border-b border-[#4a3728]/5 pb-1 animate-fade-in">
                                        <span className="text-[#8b0000] mr-2">◈</span> {log}
                                    </p>
                                )) : (
                                    <p className="text-gray-500 italic text-[10px] text-center py-10">暂无家族记载</p>
                                )}
                            </div>
                        )}
                    </div>
                </div>

                {isDashboardVisible && (
                    <div className="w-80 h-full border-l border-yellow-900/50 flex flex-col shrink-0">
                        <ClanDashboard 
                            state={state} 
                            onUpdateMember={handleUpdateMember} 
                            onAddMember={() => {}} 
                            onOpenBreakthrough={(id) => setBreakingMemberId(id)}
                        />
                    </div>
                )}
            </main>

            {isManagementVisible && (
                <ClanManagement 
                    state={state} 
                    onUpdateMember={handleUpdateMember} 
                    onUpdateBuilding={handleUpdateBuilding}
                    onAddBuilding={handleAddBuilding} 
                    onAssignBuilding={handleAssignBuilding} 
                    onClose={() => setIsManagementVisible(false)} 
                    onUnlockPosition={handleUnlockPosition}
                />
            )}

            {event && (
                <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm p-4">
                    <div className="bg-[#f4e4bc] w-full max-w-2xl p-8 rounded border-[12px] border-[#4a3728] shadow-2xl relative animate-scale-in">
                        <div className="absolute -top-10 left-1/2 -translate-x-1/2 bg-[#4a3728] text-yellow-500 px-10 py-3 rounded-b-xl font-cursive text-2xl">{event.title}</div>
                        <div className="text-[#2c1810] leading-relaxed text-lg font-serif italic mb-8 max-h-[40vh] overflow-y-auto custom-scrollbar pr-4">{event.content}</div>
                        <div className="grid grid-cols-2 gap-4">
                            <button onClick={() => handleChoice('choiceA')} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceA.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceA.effect}</p>
                            </button>
                            <button onClick={() => handleChoice('choiceB')} className="p-4 border-2 border-[#4a3728]/40 rounded hover:bg-[#4a3728] group transition-all text-left">
                                <p className="font-bold text-[#2c1810] group-hover:text-yellow-400">{event.choiceB.text}</p>
                                <p className="text-[10px] text-gray-600 group-hover:text-yellow-100/60">{event.choiceB.effect}</p>
                            </button>
                        </div>
                    </div>
                </div>
            )}

            {breakingMemberId && (
                <BreakthroughModal 
                    member={state.members.find(m => m.id === breakingMemberId)!}
                    onClose={() => setBreakingMemberId(null)}
                    onAttempt={(success) => handleBreakthroughAttempt(breakingMemberId, success)}
                />
            )}
        </div>
    );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Region, RegionType, ClanMember, RegionCategory, Realm, FactionType } from '../types';
import { REALM_ORDER } from '../constants';

interface Props {
    regions: Region[];
    members: ClanMember[];
    onSelectRegion: (region: Region | null) => void;
    onUpdateMember: (id: string, updates: Partial<ClanMember>) => void;
    onUpdateRegion: (id: string, updates: Partial<Region>) => void;
    currentRegionId: string;
}

const WorldMap: React.FC<Props> = ({ regions, members, onSelectRegion, onUpdateMember, onUpdateRegion, currentRegionId }) => {
    const [hoveredRegionId, setHoveredRegionId] = useState<string | null>(null);

    const selectedRegion = regions.find(r => r.id === currentRegionId);
    const idleMembers = members.filter(m => m.status === 'healthy' && m.realm !== Realm.Mortal && (m.assignment === 'Idle' || m.assignment === 'Patrol'));
    const hoveredRegion = regions.find(r => r.id === hoveredRegionId);

    const getDifficultyLabel = (difficulty: number, category: RegionCategory) => {
        if (difficulty === 0) return "凡尘";
        const realmIdx = Math.floor(difficulty / 10) + 1; 
        const subRealm = difficulty % 10;
        const realmName = REALM_ORDER[realmIdx] || "未知境界";

        if (category === 'Stakeholder') {
            return `${realmName}级势力`;
        }
        return `${realmName}${subRealm > 0 ? subRealm + '层' : '初期'}`;
    };

    const getFactionColor = (faction: FactionType) => {
        switch (faction) {
            case '望月李氏': return 'rgba(234, 179, 8, 0.4)'; 
            case '北寒宗': return 'rgba(59, 130, 246, 0.4)'; 
            case '天一剑宗': return 'rgba(239, 68, 68, 0.4)'; 
            case '离火门': return 'rgba(249, 115, 22, 0.4)'; 
            case '魏家': return 'rgba(139, 92, 246, 0.4)'; 
            case '邵家': return 'rgba(34, 197, 94, 0.4)'; 
            default: return 'transparent';
        }
    };

    const getTypeIcon = (type: RegionType, category: RegionCategory) => {
        if (category === 'Mystic') return '✨';
        if (category === 'Resource') {
            if (type === 'mine') return '💎';
            if (type === 'field') return '🌾';
        }
        switch (type) {
            case 'lake': return '🌊';
            case 'mountain': return '⛰️';
            case 'forest': return '🌿';
            case 'city': return '🏮';
            case 'sect': return '⛩️';
            case 'ruins': return '🏺';
            case 'cave': return '🕳️';
            case 'island': return '🏝️';
            case 'desert': return '🏜️';
            default: return '📍';
        }
    };

    const getCategorySizeClasses = (category: RegionCategory, id: string) => {
        const isHome = id === 'li_clan_home';
        switch (category) {
            case 'Stakeholder': 
                return isHome ? 'w-14 h-14 text-2xl' : 'w-12 h-12 text-xl';
            case 'Natural': 
                return 'w-11 h-11 text-lg';
            case 'Mystic': 
                return 'w-11 h-11 text-lg';
            case 'Resource': 
                return 'w-9 h-9 text-base';
            default: 
                return 'w-10 h-10 text-lg';
        }
    };

    const handleDispatch = (memberId: string, region: Region, missionType: 'Occupy' | 'Explore' | 'War' | 'Mystic') => {
        let baseTurns = 1;
        if (missionType === 'Occupy') baseTurns = 2 + Math.floor(region.difficulty / 10);
        if (missionType === 'Explore') baseTurns = 1;
        if (missionType === 'War') baseTurns = 4 + Math.floor(region.difficulty / 5);
        if (missionType === 'Mystic') baseTurns = 4;

        onUpdateMember(memberId, { assignment: 'Mission' });
        onUpdateRegion(region.id, {
            activeMission: {
                memberId,
                turnsRemaining: baseTurns,
                totalTurns: baseTurns,
                type: missionType
            }
        });
    };

    const getPanelStyle = () => {
        if (!selectedRegion) return {};
        const isRightSide = selectedRegion.x < 50;
        const isBottomSide = selectedRegion.y < 50;

        return {
            left: isRightSide ? `${selectedRegion.x}%` : 'auto',
            right: !isRightSide ? `${100 - selectedRegion.x}%` : 'auto',
            top: isBottomSide ? `${selectedRegion.y}%` : 'auto',
            bottom: !isBottomSide ? `${100 - selectedRegion.y}%` : 'auto',
            transform: `translate(${isRightSide ? '40px' : '-40px'}, ${isBottomSide ? '20px' : '-20px'})`,
        };
    };

    const factionZones = useMemo(() => {
        return regions.filter(r => r.isDiscovered && r.owner !== '无').map(r => (
            <div 
                key={`zone-${r.id}`}
                className="absolute transform -translate-x-1/2 -translate-y-1/2 rounded-full blur-[80px] pointer-events-none transition-all duration-1000"
                style={{ 
                    left: `${r.x}%`, 
                    top: `${r.y}%`, 
                    width: '300px', 
                    height: '300px', 
                    background: getFactionColor(r.owner),
                    opacity: 0.15
                }}
            />
        ));
    }, [regions]);

    return (
        <div className="relative w-full h-full parchment scroll-shadow overflow-hidden border-8 border-[#4a3728] bg-[#e6d5b8]">
            <div className="absolute inset-0 opacity-10 pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/aged-paper.png')]"></div>

            <div className="absolute inset-0 z-0">
                {factionZones}
            </div>

            <div className="absolute top-6 left-1/2 -translate-x-1/2 text-5xl font-cursive opacity-20 select-none pointer-events-none z-10">
                天罡大陆 · 九州全志
            </div>

            <svg width="100%" height="100%" className="absolute inset-0 opacity-20 pointer-events-none">
                <path d="M50,150 C150,100 250,200 450,150 S650,50 850,250" stroke="#2c1810" fill="none" strokeWidth="1" strokeDasharray="5,5" />
                <path d="M100,500 Q300,400 500,550 T900,450" stroke="#2c1810" fill="none" strokeWidth="2" opacity="0.4" />
                <circle cx="50%" cy="75%" r="15%" fill="none" stroke="rgba(234, 179, 8, 0.2)" strokeWidth="1" strokeDasharray="10,5" />
            </svg>

            {regions.map(region => {
                const isDiscovered = region.isDiscovered;
                const isHome = region.id === 'li_clan_home';
                const isOccupied = !!region.activeMission;
                const currentOwner = region.owner;
                const sizeClass = getCategorySizeClasses(region.category, region.id);

                if (!isDiscovered) {
                    return (
                        <div 
                            key={region.id}
                            className="absolute transform -translate-x-1/2 -translate-y-1/2 opacity-30 cursor-help group"
                            style={{ left: `${region.x}%`, top: `${region.y}%` }}
                        >
                            <div className="w-8 h-8 flex items-center justify-center bg-black/10 rounded-full text-lg grayscale blur-[0.5px] hover:grayscale-0 hover:blur-0 transition-all">
                                ❔
                            </div>
                            <div className="absolute hidden group-hover:block top-10 left-1/2 -translate-x-1/2 bg-black/80 text-white text-[8px] px-2 py-1 rounded whitespace-nowrap z-50">
                                动用昊天镜可照破此地虚妄
                            </div>
                        </div>
                    );
                }

                return (
                    <button
                        key={region.id}
                        onClick={() => onSelectRegion(region)}
                        onMouseEnter={() => setHoveredRegionId(region.id)}
                        onMouseLeave={() => setHoveredRegionId(null)}
                        className={`absolute transform -translate-x-1/2 -translate-y-1/2 transition-all duration-500 group
                            ${currentRegionId === region.id ? 'scale-125 z-20' : 'hover:scale-110 z-10'}`}
                        style={{ left: `${region.x}%`, top: `${region.y}%` }}
                    >
                        <div className="flex flex-col items-center">
                            {region.category === 'Resource' && (
                                <div className="w-8 h-1 bg-black/20 rounded-full overflow-hidden mb-1 border border-[#4a3728]/20">
                                    <div 
                                        className={`h-full ${region.owner === '望月李氏' ? 'bg-yellow-600 shadow-[0_0_5px_rgba(234,179,8,0.5)]' : 'bg-gray-400'} transition-all`} 
                                        style={{ width: `${region.owner === '望月李氏' ? 100 : 0}%` }}
                                    ></div>
                                </div>
                            )}

                            <div className={`${sizeClass} flex items-center justify-center rounded-full border-2 relative transition-all duration-300
                                ${isHome ? 'bg-amber-900 border-yellow-500 shadow-[0_0_20px_rgba(245,158,11,0.6)] ring-2 ring-yellow-500/20' : 
                                  (region.category === 'Mystic' ? 'bg-purple-900 border-purple-400 shadow-[0_0_15px_rgba(168,85,247,0.5)] animate-pulse' :
                                  (currentRegionId === region.id ? 'bg-red-900 border-yellow-400 shadow-[0_0_20px_rgba(234,179,8,0.6)]' : 
                                  (region.category === 'Stakeholder' ? 'bg-indigo-900 border-indigo-400 shadow-md' : 'bg-[#4a3728] border-[#2c1810]')))} 
                                shadow-lg`}>
                                {getTypeIcon(region.type, region.category)}

                                {isOccupied && (
                                    <div className="absolute -top-2 -right-2 w-5 h-5 bg-orange-600 rounded-full border border-white text-[10px] flex items-center justify-center animate-bounce text-white font-bold">
                                        ⏳
                                    </div>
                                )}

                                {currentOwner !== '无' && !isHome && (
                                    <div 
                                        className="absolute -bottom-1 -right-1 w-4 h-4 rounded-full border border-white/50 shadow-sm"
                                        style={{ backgroundColor: getFactionColor(currentOwner).replace('0.4', '1') }}
                                    />
                                )}
                            </div>
                            <div className="mt-1">
                                <span className={`text-[9px] font-bold bg-[#f4e4bc]/95 px-1.5 py-0.5 rounded border border-[#4a3728] whitespace-nowrap shadow-sm
                                    ${currentRegionId === region.id || isHome || region.owner === '望月李氏' ? 'text-amber-900 border-amber-900 ring-1 ring-amber-400' : 'text-[#2c1810]'}`}>
                                    {region.name}
                                </span>
                            </div>
                        </div>
                    </button>
                );
            })}

            {hoveredRegion && hoveredRegionId !== currentRegionId && hoveredRegion.isDiscovered && (
                <div 
                    className="absolute z-[100] pointer-events-none bg-[#1e1410] text-white p-3 rounded-md shadow-[0_10px_30px_rgba(0,0,0,0.6)] border border-yellow-900/40 min-w-[150px] animate-fade-in"
                    style={{ left: `${hoveredRegion.x}%`, top: `${hoveredRegion.y - 12}%`, transform: 'translateX(-50%)' }}
                >
                    <div className="flex justify-between items-center mb-1">
                        <p className="text-xs font-bold text-yellow-500">{hoveredRegion.name}</p>
                        <span className="text-[8px] bg-yellow-900/30 px-1 rounded text-yellow-600">
                            {getDifficultyLabel(hoveredRegion.difficulty, hoveredRegion.category)}
                        </span>
                    </div>
                    <p className="text-[9px] text-gray-400 mb-1">所属：<span className="text-orange-400 font-bold">{hoveredRegion.owner}</span></p>
                    <div className="text-[8px] text-gray-500 italic line-clamp-2">{hoveredRegion.description}</div>
                </div>
            )}

            {selectedRegion && selectedRegion.isDiscovered && (
                <div 
                    className={`absolute z-30 animate-scale-in flex flex-col pointer-events-auto`}
                    style={getPanelStyle()}
                >
                    <div className="w-72 sm:w-80 bg-[#1e1410] border-2 border-yellow-900/40 rounded-lg shadow-[0_20px_50px_rgba(0,0,0,0.8)] overflow-hidden flex flex-col max-h-[70vh]">
                        <div className="p-3 border-b border-yellow-900/20 bg-[#2c1810]/80 flex justify-between items-center shrink-0">
                            <div className="flex items-center gap-2">
                                <div className="text-lg">{getTypeIcon(selectedRegion.type, selectedRegion.category)}</div>
                                <div>
                                    <h3 className="text-yellow-500 font-bold text-sm">
                                        {selectedRegion.name}
                                    </h3>
                                    <p className="text-[9px] text-yellow-800 uppercase tracking-widest font-bold">
                                        {getDifficultyLabel(selectedRegion.difficulty, selectedRegion.category)}
                                    </p>
                                </div>
                            </div>
                            <button 
                                onClick={(e) => { e.stopPropagation(); onSelectRegion(null); }}
                                className="w-8 h-8 flex items-center justify-center rounded-full hover:bg-red-900/30 text-gray-500 hover:text-red-500 transition-colors text-xl font-bold"
                            >
                                ×
                            </button>
                        </div>

                        <div className="flex-1 overflow-y-auto p-4 space-y-4 bg-[#1e1410]/95 backdrop-blur-sm custom-scrollbar">
                            <p className="text-[11px] text-gray-400 italic leading-relaxed border-l-2 border-yellow-900/30 pl-2 py-1">
                                {selectedRegion.description}
                            </p>

                            <div className="flex flex-wrap gap-1.5">
                                {selectedRegion.resources.map(r => (
                                    <span key={r} className="bg-yellow-900/10 text-yellow-700 px-2 py-0.5 rounded text-[9px] border border-yellow-900/10 font-bold">
                                        • {r}
                                    </span>
                                ))}
                            </div>

                            <div className="pt-2 border-t border-yellow-900/10">
                                {selectedRegion.activeMission ? (
                                    <div className="p-4 bg-orange-900/10 rounded border border-orange-900/20 text-center space-y-2">
                                        <p className="text-xs text-orange-400 font-bold">
                                            {selectedRegion.activeMission.type === 'Occupy' ? '占领中...' : 
                                             selectedRegion.activeMission.type === 'War' ? '攻打中...' : 
                                             selectedRegion.activeMission.type === 'Mystic' ? '联合探索中...' : '探索中...'}
                                        </p>
                                        <div className="w-full bg-black/40 h-2 rounded-full overflow-hidden">
                                            <div 
                                                className="h-full bg-orange-500 shadow-[0_0_10px_rgba(249,115,22,0.5)]" 
                                                style={{ width: `${(1 - selectedRegion.activeMission.turnsRemaining / selectedRegion.activeMission.totalTurns) * 100}%` }}
                                            ></div>
                                        </div>
                                        <p className="text-[10px] text-gray-500">还需 {selectedRegion.activeMission.turnsRemaining} 季</p>
                                    </div>
                                ) : (
                                    <>
                                        {selectedRegion.category !== 'Stakeholder' && selectedRegion.id !== 'li_clan_home' ? (
                                            <>
                                                <div className="flex justify-between items-center mb-3">
                                                    <h4 className="text-[10px] text-yellow-600 font-bold uppercase">派遣动作</h4>
                                                    <span className="text-[9px] text-gray-600">所属: {selectedRegion.owner}</span>
                                                </div>

                                                <div className="space-y-1.5">
                                                    {idleMembers.length > 0 ? (
                                                        idleMembers.map(member => {
                                                            let actionType: 'Occupy' | 'Explore' | 'War' | 'Mystic' = 'Explore';
                                                            let actionLabel = '探索';

                                                            if (selectedRegion.category === 'Resource') {
                                                                if (selectedRegion.owner === '无') {
                                                                    actionType = 'Occupy';
                                                                    actionLabel = '占领';
                                                                } else if (selectedRegion.owner !== '望月李氏') {
                                                                    actionType = 'War';
                                                                    actionLabel = '攻打';
                                                                } else {
                                                                    actionLabel = '驻守 (增益)';
                                                                    actionType = 'Occupy';
                                                                }
                                                            } else if (selectedRegion.category === 'Mystic') {
                                                                actionType = 'Mystic';
                                                                actionLabel = '进入秘境';
                                                            }

                                                            return (
                                                                <div key={member.id} className="bg-black/30 border border-yellow-900/5 hover:border-yellow-700/30 rounded p-2.5 flex justify-between items-center transition-all group">
                                                                    <div className="flex flex-col">
                                                                        <span className="text-xs text-yellow-100 group-hover:text-yellow-500 font-bold">{member.name}</span>
                                                                        <span className="text-[9px] text-gray-500">{member.realm === Realm.Mortal ? '凡人' : `${member.realm}${member.subRealm}层`}</span>
                                                                    </div>
                                                                    <button 
                                                                        onClick={() => handleDispatch(member.id, selectedRegion, actionType)}
                                                                        className={`px-3 py-1 text-[10px] rounded border transition-all font-bold 
                                                                            ${actionType === 'War' ? 'bg-red-900/40 border-red-700 text-red-500 hover:bg-red-700 hover:text-white' : 
                                                                              (actionType === 'Mystic' ? 'bg-purple-900/40 border-purple-700 text-purple-400 hover:bg-purple-700 hover:text-white' : 
                                                                              'bg-yellow-900/20 border-yellow-900/30 text-yellow-600 hover:bg-yellow-700 hover:text-white')}`}
                                                                    >
                                                                        {actionLabel}
                                                                    </button>
                                                                </div>
                                                            );
                                                        })
                                                    ) : (
                                                        <p className="text-center py-4 text-[11px] text-gray-700 italic border border-dashed border-white/5 rounded">族中暂时无可用修士（凡人不可执行派遣任务）</p>
                                                    )}
                                                </div>
                                            </>
                                        ) : (
                                            <div className="p-4 bg-blue-900/10 rounded border border-blue-900/20 text-center">
                                                <p className="text-xs text-blue-400 font-bold">
                                                    {selectedRegion.id === 'li_clan_home' ? '李氏祖基，万世不易' : '由于阵法笼罩或势力对等，暂不可交互'}
                                                </p>
                                            </div>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>

                        <div className="p-2 bg-black/60 text-center border-t border-yellow-900/10 shrink-0">
                            <p className="text-[9px] text-gray-600 uppercase font-bold tracking-widest">
                                {selectedRegion.category === 'Resource' ? '✨ 家族产业' : (selectedRegion.category === 'Natural' ? '🏔️ 名山大川' : (selectedRegion.category === 'Mystic' ? '🏺 古老传承' : '🏰 势力枢纽'))}
                            </p>
                        </div>
                    </div>
                </div>
            )}

            <style>{`
                @keyframes scale-in {
                    from { opacity: 0; transform: scale(0.95); }
                    to { opacity: 1; transform: scale(1); }
                }
                .animate-scale-in {
                    animation: scale-in 0.2s cubic-bezier(0.16, 1, 0.3, 1) forwards;
                }
                .custom-scrollbar::-webkit-scrollbar { width: 4px; }
                .custom-scrollbar::-webkit-scrollbar-thumb { background: #3d2b24; border-radius: 10px; }
                @keyframes fade-in { from { opacity: 0; } to { opacity: 1; } }
                .animate-fade-in { animation: fade-in 0.2s ease-out forwards; }
            `}</style>
        </div>
    );
};

export default WorldMap;
